INSERT INTO `posts` VALUES (1,'PTIT sẽ tuyển sinh 7 chương trình đào tạo mới đón đầu xu hướng công nghệ và sáng tạo số','ptit-se-tuyen-sinh-7-chuong-trinh-dao-tao-moi-don-dau-xu-huong-cong-nghe-va-sang-tao-so','Năm 2026, Học viện Công nghệ Bưu chính Viễn thông (PTIT) sẽ mở thêm 7 chương trình đào tạo mới, trải rộng từ công nghệ cao, kinh tế số đến công nghiệp sáng tạo. Đây được xem là bước đi nhằm đón đầu nhu cầu nhân lực trong bối cảnh Việt Nam thúc đẩy phát triển khoa học công nghệ, đổi mới sáng tạo và chuyển đổi số.','<p style=\"text-align: justify\"><em><strong>Năm 2026, Học viện Công nghệ Bưu chính Viễn thông (PTIT) sẽ mở thêm 7 chương trình đào tạo mới, trải rộng từ công nghệ cao, kinh tế số đến công nghiệp sáng tạo. Đây được xem là bước đi nhằm đón đầu nhu cầu nhân lực trong bối cảnh Việt Nam thúc đẩy phát triển khoa học công nghệ, đổi mới sáng tạo và chuyển đổi số.</strong></em></p>\n<p style=\"text-align: justify\"><strong>Tăng cường mở thêm các chương trình đào tạo công nghệ cao, công nghệ chiến lược</strong></p>\n<p style=\"text-align: justify\">Trong nhóm các chương trình công nghệ cao, PTIT sẽ triển khai hai chương trình đào tạo mới gồm <strong>Kỹ thuật Truyền thông Hàng không Vũ trụ và UAV & Robot di động tự hành</strong>. Đây là chương trình mới lần đầu được đưa vào giảng dạy ở Việt Nam, tích hợp kiến thức về viễn thông, trí tuệ nhân tạo, cảm biến và điều khiển tự động.</p>\n<p style=\"text-align: justify\"><img class=\"aligncenter size-full\" src=\"/images/post_1/anh-1.jpg\" alt=\"\" /></p>\n<p style=\"text-align: justify\"><em>Một giờ học thực hành của sinh viên PTIT</em></p>\n<p style=\"text-align: justify\">Các công nghệ này hiện được ứng dụng trong nhiều lĩnh vực như giao thông thông minh, công nghiệp, quản lý hạ tầng, cứu hộ khẩn cấp hay quốc phòng. Theo PTIT, việc đưa các chương trình này vào đào tạo nhằm chuẩn bị nguồn nhân lực cho xu hướng phát triển không gian số và hệ thống tự hành trong tương lai.</p>\n<p style=\"text-align: justify\"><strong>Các chương trình kinh tế – quản trị dẫn dắt đổi mới trong thời đại số</strong></p>\n<p style=\"text-align: justify\">Ở khối kinh tế, Học viện đã công bố mở ngành Tài chính Ngân hàng với chương trình <strong>Phân tích dữ liệu trong tài chính, kinh doanh</strong>. Bên cạnh đó là hai chương trình đào tạo mới gồm <strong>Quản trị Đổi mới sáng tạo & Khởi nghiệp</strong> và <strong>Logistics trong kinh tế tầm thấp.</strong></p>\n<p style=\"text-align: justify\">Chương trình Phân tích dữ liệu trong tài chính, kinh doanh của PTIT sẽ trang bị cho sinh viên nền tảng về tài chính – ngân hàng, kinh tế học, đồng thời tích hợp các kỹ năng về phân tích dữ liệu, thống kê, trí tuệ nhân tạo và ứng dụng công nghệ.</p>\n<p style=\"text-align: justify\"><img class=\"aligncenter size-full\" src=\"/images/post_1/anh-3.jpg\" alt=\"\" /></p>\n<p style=\"text-align: justify\">Tại Việt Nam, nhân lực đáp ứng đồng thời cả ba yếu tố này vẫn còn thiếu. Nhiều sinh viên tốt nghiệp các ngành tài chính truyền thống còn hạn chế về kỹ năng dữ liệu, trong khi sinh viên công nghệ thông tin lại thiếu nền tảng nghiệp vụ tài chính. Khoảng trống này khiến doanh nghiệp phải mất thêm thời gian đào tạo lại hoặc tìm kiếm nhân sự từ thị trường quốc tế. Vì thế, việc mở chương trình đào tạo chuyên sâu về phân tích dữ liệu trong tài chính, kinh doanh được xem là hướng đi tiên phong và cấp thiết.</p>\n<p style=\"text-align: justify\">Trong bối cảnh cạnh tranh số ngày càng gay gắt, năng lực đổi mới sáng tạo được xem là yếu tố quyết định khả năng thích ứng và tăng trưởng của doanh nghiệp. Việc quyết định mở chương trình đào tạo bài bản về Quản trị Đổi mới sáng tạo và Khởi nghiệp của PTIT (ngành Quản trị Kinh doanh) không chỉ giúp hình thành tư duy phát triển sản phẩm, mô hình kinh doanh mới mà còn góp phần thúc đẩy quá trình thương mại hóa công nghệ trong nền kinh tế. Đồng thời, đây cũng là nền tảng quan trọng để hình thành tư duy khởi nghiệp, giúp người học có khả năng nhận diện cơ hội thị trường, xây dựng và vận hành các dự án kinh doanh trong môi trường số.</p>\n<p style=\"text-align: justify\">Trong khi đó, Logistics trong kinh tế tầm thấp là lĩnh vực mới gắn với hoạt động kinh tế diễn ra trong không phận thấp, liên quan đến UAV, thiết bị bay tự hành và hệ thống điều phối bay thông minh. Đây được xem là lĩnh vực có nhiều tiềm năng trong tương lai, đặc biệt ở các hoạt động giao hàng, giám sát hạ tầng và đô thị thông minh.</p>\n<p style=\"text-align: justify\"><strong>Đẩy mạnh công nghiệp sáng tạo và nội dung số</strong></p>\n<p style=\"text-align: justify\">Đáng chú ý, PTIT sẽ mở rộng đào tạo trong lĩnh vực công nghệ văn hóa với hai chương trình mới gồm <strong>Công nghệ công nghiệp văn hóa số</strong> (định hướng điện ảnh) và <strong>Thiết kế đồ họa game</strong>.</p>\n<p style=\"text-align: justify\">Công nghệ công nghiệp văn hóa số (định hướng điện ảnh) kết hợp giữa công nghệ và nghệ thuật, hướng tới đào tạo nhân lực tham gia toàn bộ quy trình sản xuất nội dung số, từ xây dựng kịch bản, quay dựng, hậu kỳ đến phát hành trên nền tảng số.</p>\n<p style=\"text-align: justify\"><img class=\"alignnone size-full\" src=\"/images/post_1/anh-4.jpg\" alt=\"\" /></p>\n<p style=\"text-align: justify\"><em>Tác phẩm phim ngắn “Con đường của thế hệ” của sinh viên PTIT được Ban Tổ chức Liên hoan phim quốc tế Viet Culture in Motion 2026 tuyển chọn vào danh sách các tác phẩm được trình chiếu tại Pháp.</em></p>\n<p style=\"text-align: justify\">Trong bối cảnh các nền tảng streaming, video trực tuyến và mạng xã hội phát triển mạnh, nhu cầu nhân lực cho ngành công nghiệp nội dung số ngày càng tăng, đặc biệt ở các vị trí liên quan đến kỹ xảo, dựng phim, xử lý hình ảnh và âm thanh số.</p>\n<p style=\"text-align: justify\">Song song đó, chương trình Thiết kế đồ họa game hướng tới đáp ứng nhu cầu nhân lực cho ngành công nghiệp game và giải trí số, lĩnh vực đang có tốc độ tăng trưởng cao tại Việt Nam và khu vực.</p>\n<p style=\"text-align: justify\"><strong>Hướng tới hệ sinh thái đào tạo liên ngành</strong></p>\n<p style=\"text-align: justify\">Việc đồng thời mở các ngành thuộc cả khối công nghệ, kinh tế và văn hoá cho thấy định hướng xây dựng hệ sinh thái đào tạo liên ngành của PTIT, kết nối giữa công nghệ, đổi mới sáng tạo và ứng dụng thực tiễn. Không chỉ mở rộng lựa chọn cho thí sinh, các ngành học của PTIT còn góp phần chuẩn bị nguồn nhân lực cho các lĩnh vực được dự báo sẽ đóng vai trò quan trọng trong cấu trúc kinh tế tương lai.</p>\n<p style=\"text-align: justify\">Về phương thức tuyển sinh, các ngành mới dự kiến sử dụng 5 phương thức xét tuyển hiện hành của Học viện. Tổ hợp xét tuyển gồm A00 (Toán, Lý, Hóa), A01 (Toán, Lý, Tiếng Anh), X06 (Toán, Lý, Tin), X26 (Toán, Tin, Tiếng Anh). Riêng một số ngành thuộc khối kinh tế bổ sung thêm tổ hợp D01 (Toán, Văn, Tiếng Anh).</p>','/images/post_1/anh-1.jpg','Tin tức','2026-05-07','huongbtb'),(2,'Tổng Bí thư, Chủ tịch nước Tô Lâm chứng kiến trao thỏa thuận hợp tác giữa Học viện Công nghệ Bưu chính Viễn thông (PTIT) và Học viện Công nghệ Ấn Độ Madras (IIT Madras) tại Diễn đàn Đổi mới sáng tạo Việt Nam – Ấn Độ','tong-bi-thu-chu-tich-nuoc-to-lam-chung-kien-trao-thoa-thuan-hop-tac-giua-hoc-vien-cong-nghe-buu-chinh-vien-thong-ptit-va-hoc-vien-cong-nghe-an-do-madras-iit-madras-tai-dien-dan-doi-moi-sang-tao','Trong khuôn khổ chuyến thăm cấp Nhà nước tới Ấn Độ của Tổng Bí thư, Chủ tịch nước Tô Lâm, chiều ngày 06/5 tại New Delhi, Bộ Khoa học và Công nghệ Việt Nam phối hợp với Bộ Điện tử và Công nghệ thông tin Ấn Độ tổ chức Diễn đàn Đổi mới sáng tạo...','<p style=\"text-align: justify\"><span style=\"font-weight: 400\">Trong khuôn khổ chuyến thăm cấp Nhà nước tới Ấn Độ của Tổng Bí thư, Chủ tịch nước Tô Lâm, chiều ngày 06/5 tại New Delhi, Bộ Khoa học và Công nghệ Việt Nam phối hợp với Bộ Điện tử và Công nghệ thông tin Ấn Độ tổ chức Diễn đàn Đổi mới sáng tạo Việt Nam – Ấn Độ với chủ đề “Hợp tác phát triển nguồn nhân lực, khoa học, công nghệ, đổi mới sáng tạo và chuyển đổi số”.</span></p>\n<p style=\"text-align: justify\"><span style=\"font-weight: 400\">Tại Diễn đàn, Tổng Bí thư, Chủ tịch nước Tô Lâm cùng Bộ trưởng Bộ Khoa học và Công nghệ Việt Nam, Bộ trưởng Bộ Điện tử và Công nghệ thông tin Ấn Độ đã chứng kiến lễ trao các văn kiện hợp tác giữa các trường đại học, viện nghiên cứu, hiệp hội và doanh nghiệp của hai nước. Trong đó có thỏa thuận hợp tác giữa Học viện Công nghệ Bưu chính Viễn thông (PTIT) và Học viện Công nghệ Ấn Độ Madras (IIT Madras) – một trong những trường đại học kỹ thuật hàng đầu Ấn Độ.</span></p>\n\n<div id=\"attachment_40703\" class=\"wp-caption aligncenter\">\n    <img class=\"wp-image-40703 size-full\" src=\"/images/post_2/2385451164926226827.jpg\" alt=\"\" width=\"2560\" height=\"1707\" />\n    <p id=\"caption-attachment-40703\" class=\"wp-caption-text\">Tổng Bí thư, Chủ tịch nước Tô Lâm chứng kiến trao các văn kiện, thỏa thuận hợp tác giữa Học viện Công nghệ Bưu chính Viễn thông (PTIT) và Học viện Công nghệ Ấn Độ Madras (IIT Madras)</p>\n</div>\n\n<p style=\"text-align: justify\"><span style=\"font-weight: 400\">Thỏa thuận hợp tác giữa hai bên hướng tới thúc đẩy trao đổi sinh viên, giảng viên và cán bộ nghiên cứu; triển khai các dự án nghiên cứu chung; tổ chức hội thảo, tọa đàm học thuật; đồng thời tăng cường chia sẻ tài nguyên học thuật, kinh nghiệm đào tạo và nghiên cứu trong các lĩnh vực công nghệ. Việc hợp tác với IIT Madras được kỳ vọng sẽ mở ra nhiều cơ hội để PTIT mở rộng mạng lưới hợp tác quốc tế trong các lĩnh vực công nghệ chiến lược, đồng thời thúc đẩy kết nối giữa đào tạo, nghiên cứu và đổi mới sáng tạo theo xu hướng quốc tế.</span></p>\n<p style=\"text-align: justify\"><span style=\"font-weight: 400\">Được biết, Indian Institute of Technology Madras (IIT Madras) là một trong những trường kỹ thuật danh tiếng nhất của Ấn Độ, được thành lập năm 1959 tại Chennai. Trường nổi bật với thế mạnh nghiên cứu và đào tạo trong AI, khoa học máy tính, bán dẫn, robot, năng lượng, hàng không vũ trụ và công nghệ viễn thông. IIT Madras hiện sở hữu hệ sinh thái đổi mới sáng tạo hàng đầu Ấn Độ, với vườn ươm startup IITM Incubation Cell, đã hỗ trợ hàng trăm startup công nghệ sâu (deep-tech). Theo bảng xếp hạng quốc gia NIRF 2025 của Bộ Giáo dục Ấn Độ, IIT Madras tiếp tục đứng số 1 toàn Ấn Độ ở cả nhóm “Overall” và “Engineering”. Trên bảng xếp hạng quốc tế QS World University Rankings 2026, trường xếp #180 thế giới. </span></p>\n<p style=\"text-align: justify\"><span style=\"font-weight: 400\">Diễn đàn Đổi mới sáng tạo Việt Nam – Ấn Độ năm 2026 diễn ra trong bối cảnh hai nước thúc đẩy mạnh mẽ hợp tác về khoa học công nghệ, đổi mới sáng tạo và chuyển đổi số. Phát biểu tại Diễn đàn, Tổng Bí thư, Chủ tịch nước Tô Lâm nhấn mạnh khoa học công nghệ, đổi mới sáng tạo và nguồn nhân lực chất lượng cao sẽ trở thành những “chất liệu mới” của quan hệ hợp tác chiến lược Việt Nam – Ấn Độ trong giai đoạn phát triển mới.</span></p>\n\n<div id=\"attachment_40707\" class=\"wp-caption aligncenter\">\n    <img class=\"wp-image-40707 size-full\" src=\"/images/post_2/888.png\" alt=\"\" width=\"1000\" height=\"695\" />\n    <p id=\"caption-attachment-40707\" class=\"wp-caption-text\">Tổng Bí thư, Chủ tịch nước Tô Lâm và các đại biểu.</p>\n</div>\n\n<p style=\"text-align: justify\"><span style=\"font-weight: 400\">Việc PTIT tham gia trao thỏa thuận hợp tác tại Diễn đàn tiếp tục khẳng định vai trò chủ động của Học viện trong thúc đẩy hợp tác quốc tế, phát triển nguồn nhân lực công nghệ cao và mở rộng kết nối với các đối tác học thuật, công nghệ hàng đầu thế giới.</span></p>\n\n<div id=\"attachment_40704\" class=\"wp-caption alignnone\">\n    <img class=\"wp-image-40704 size-full\" src=\"/images/post_2/1917732620491266169-3.jpg\" alt=\"\" width=\"2560\" height=\"1707\" />\n    <p id=\"caption-attachment-40704\" class=\"wp-caption-text\">Đoàn PTIT và IIT Madras chụp ảnh lưu niệm</p>\n</div>','/images/post_2/2385451164926226827.jpg','Tin tức','2026-05-07','huongbtb'),(3,'PTIT làm việc với C-DAC, thúc đẩy hợp tác đào tạo công nghệ và phát triển nguồn nhân lực số trước thềm Diễn đàn Đổi mới sáng tạo Việt Nam – Ấn Độ','ptit-lam-viec-voi-c-dac-thuc-day-hop-tac-dao-tao-cong-nghe-va-phat-trien-nguon-nhan-luc-so-truoc-them-dien-dan-doi-moi-sang-tao-viet-nam-an-do','Trong bối cảnh thúc đẩy hợp tác công nghệ giữa Việt Nam và Ấn Độ trước thềm Diễn đàn Đổi mới sáng tạo Việt Nam – Ấn Độ, đoàn công tác của Học viện Công nghệ Bưu chính Viễn thông (PTIT) do PGS. TS Đặng Hoài Bắc dẫn đầu đã có buổi làm việc với Trung tâm Phát triển Công nghệ Điện toán Tiên tiến (C-DAC)...','<p style=\"text-align: justify\">Trong bối cảnh thúc đẩy hợp tác công nghệ giữa Việt Nam và Ấn Độ trước thềm Diễn đàn Đổi mới sáng tạo Việt Nam – Ấn Độ, đoàn công tác của Học viện Công nghệ Bưu chính Viễn thông (PTIT) do PGS. TS Đặng Hoài Bắc dẫn đầu đã có buổi làm việc với Trung tâm Phát triển Công nghệ Điện toán Tiên tiến (C-DAC) tại New Delhi, tập trung trao đổi về định hướng phát triển đào tạo công nghệ cao, trí tuệ nhân tạo và mở rộng hợp tác trong giai đoạn tới.</p>\n<p style=\"text-align: justify\">C-DAC là tổ chức nghiên cứu và phát triển hàng đầu của Ấn Độ trong lĩnh vực công nghệ thông tin và điện tử, trực thuộc Bộ Điện tử và Công nghệ Thông tin (MeitY), nổi bật với năng lực về tính toán hiệu năng cao, trí tuệ nhân tạo, an ninh mạng và thiết kế vi mạch. Trên nền tảng thế mạnh này, hợp tác giữa PTIT và C-DAC thời gian qua được đánh giá là một trong những mô hình tiêu biểu trong phát triển nguồn nhân lực công nghệ giữa hai quốc gia.</p>\n<p style=\"text-align: justify\">Trên cơ sở triển khai dự án hợp tác ASEAN – Ấn Độ, hai bên đã xây dựng và vận hành Trung tâm Xuất sắc về đào tạo và phát triển phần mềm (CESDT) tại cơ sở TP. Hồ Chí Minh của Học viện. Mô hình này đã ghi nhận những kết quả bước đầu đáng chú ý, với gần 1.000 học viên được đào tạo, đội ngũ giảng viên nòng cốt được hình thành từ chương trình Master Trainer tại Ấn Độ, cùng các chương trình đào tạo được nội địa hóa theo nhu cầu thực tiễn của Việt Nam.</p>\n\n<div id=\"attachment_40690\" class=\"wp-caption aligncenter\">\n    <img class=\"wp-image-40690 size-full\" src=\"/images/post_3/1111.jpg\" alt=\"\" width=\"2048\" height=\"956\" />\n    <p id=\"caption-attachment-40690\" class=\"wp-caption-text\">Toàn cảnh buổi làm việc</p>\n</div>\n\n<p style=\"text-align: justify\">Từ thực tiễn hợp tác, PGS.TS Đặng Hoài Bắc – Giám đốc Học viện cho rằng CESDT không chỉ là một dự án đào tạo mà đang dần trở thành mô hình hợp tác chiến lược trong phát triển nguồn nhân lực số. Nhận thấy nhu cầu ngày càng lớn về nguồn nhân lực trong các lĩnh vực AI, bán dẫn, hệ thống nhúng và chuyển đổi số, ông bày tỏ kỳ vọng hai bên sẽ tiếp tục mở rộng hợp tác theo hướng cập nhật chương trình đào tạo gắn với thị trường, đồng thời phát triển các khóa đào tạo chuyên sâu theo tiêu chuẩn C-DAC.</p>\n<p style=\"text-align: justify\">Bên cạnh đó, các nội dung về trao đổi sinh viên, tổ chức chương trình thực tập tại doanh nghiệp công nghệ Ấn Độ, cũng như khả năng xây dựng các phòng thí nghiệm chung trong các lĩnh vực như trí tuệ nhân tạo, thiết kế vi mạch, UAV và công nghệ hàng không vũ trụ cũng được hai bên trao đổi. Việc mở rộng mô hình đào tạo CESDT ra cơ sở Hà Nội của Học viện và phát triển thêm các chương trình đào tạo dài hạn theo chuẩn quốc tế được xem là những hướng đi tiềm năng.</p>\n\n<div id=\"attachment_40689\" class=\"wp-caption aligncenter\">\n    <img class=\"wp-image-40689 size-full\" src=\"/images/post_3/2222.jpg\" alt=\"\" width=\"2048\" height=\"1046\" />\n    <p id=\"caption-attachment-40689\" class=\"wp-caption-text\">TS. Đỗ Trung Anh, Giám đốc Trung tâm Đổi mới sáng tạo và Khởi nghiệp, PTIT và Ông Abhinav Dixit, Trưởng phòng Hợp tác Quốc tế, Giám đốc Trung tâm CDAC Patna trao Chứng nhận Trung tâm Đào tạo Ủy quyền Quốc tế của C-DAC</p>\n</div>\n\n<p style=\"text-align: justify\">Từ góc nhìn chiến lược, phía PTIT đánh giá sự kết hợp giữa năng lực công nghệ của Ấn Độ và nhu cầu phát triển mạnh mẽ của Việt Nam có thể tạo ra một mô hình hợp tác bền vững, không chỉ trong đào tạo mà còn trong nghiên cứu và chuyển giao công nghệ. Đây cũng là nền tảng để hai bên tiếp tục mở rộng hợp tác trong các lĩnh vực công nghệ mũi nhọn trong thời gian tới.</p>\n\n<div id=\"attachment_40688\" class=\"wp-caption aligncenter\">\n    <img class=\"wp-image-40688 size-full\" src=\"/images/post_3/3333.jpg\" alt=\"\" width=\"2048\" height=\"956\" />\n    <p id=\"caption-attachment-40688\" class=\"wp-caption-text\">PGS. TS Đặng Hoài Bắc, Giám đốc Học viện và Ông Jitendra Singh, Trưởng Trung tâm CDAC Delhi trao đổi quà lưu niệm</p>\n</div>\n\n<p style=\"text-align: justify\">Buổi làm việc là bước chuẩn bị quan trọng, góp phần làm sâu sắc thêm nội dung hợp tác giữa PTIT và C-DAC, đồng thời mở ra các hướng kết nối thực chất trước thềm Diễn đàn Đổi mới sáng tạo Việt Nam – Ấn Độ trong thời gian tới.</p>','/images/post_3/2222.jpg','Tin tức','2026-05-06','huongbtb'),(4,'PTIT tham gia đoàn công tác Bộ Khoa học và Công nghệ làm việc với IHFC (IIT Delhi), thúc đẩy kết nối hệ sinh thái deep-tech Việt Nam – Ấn Độ','ptit-tham-gia-doan-cong-tac-bo-khoa-hoc-va-cong-nghe-lam-viec-voi-ihfc-iit-delhi-thuc-day-ket-noi-he-sinh-thai-deep-tech-viet-nam-an-do','Trong khuôn khổ chuyến thăm cấp Nhà nước tới Ấn Độ của Tổng Bí thư, Chủ tịch nước Tô Lâm, đoàn công tác của Học viện Công nghệ Bưu chính Viễn thông (PTIT) đã tham gia cùng đoàn công tác của Bộ Khoa học và Công nghệ Việt Nam làm việc với Trung tâm Công nghệ I-Hub (IHFC) thuộc Học viện Công nghệ Ấn Độ Delhi (IIT Delhi).','<p style=\"text-align: justify\">Trong khuôn khổ chuyến thăm cấp Nhà nước tới Ấn Độ của Tổng Bí thư, Chủ tịch nước Tô Lâm, đoàn công tác của Học viện Công nghệ Bưu chính Viễn thông (PTIT) đã tham gia cùng đoàn công tác của Bộ Khoa học và Công nghệ Việt Nam làm việc với Trung tâm Công nghệ I-Hub (IHFC) thuộc Học viện Công nghệ Ấn Độ Delhi (IIT Delhi), tập trung vào các nội dung hợp tác phát triển hệ sinh thái công nghệ sâu (deep-tech), robot và trí tuệ nhân tạo.</p>\n<p style=\"text-align: justify\">IHFC là trung tâm đổi mới sáng tạo về điều khiển học vật lý (Cyber-Physical Systems - CPS) được thành lập bởi IIT Delhi với sự hỗ trợ của Chính phủ Ấn Độ. Trung tâm đóng vai trò hạt nhân trong việc kết nối giữa nghiên cứu hàn lâm và ứng dụng công nghiệp, đặc biệt là trong các lĩnh vực robot y tế, robot nông nghiệp, robot phục vụ sản xuất thông minh và các giải pháp AI ứng dụng.</p>\n\n<div id=\"attachment_40693\" class=\"wp-caption aligncenter\">\n    <img class=\"wp-image-40693 size-full\" src=\"/images/post_4/6666.jpg\" alt=\"\" width=\"2048\" height=\"1365\" />\n    <p id=\"caption-attachment-40693\" class=\"wp-caption-text\">Đoàn công tác làm việc tại IHFC (IIT Delhi)</p>\n</div>\n\n<p style=\"text-align: justify\">Tại buổi làm việc, đại diện PTIT và IHFC đã trao đổi sâu về mô hình vận hành các trung tâm đổi mới sáng tạo, cách thức thúc đẩy các dự án nghiên cứu từ phòng thí nghiệm ra thị trường và cơ chế hỗ trợ các startup deep-tech. PGS. TS Đặng Hoài Bắc, Giám đốc Học viện bày tỏ mong muốn hai bên sẽ triển khai các hoạt động kết nối cụ thể, đặc biệt là trong việc trao đổi chuyên gia, phối hợp tổ chức các chương trình đào tạo ngắn hạn và dài hạn về robot, AI, cũng như xem xét khả năng hình thành các nhóm nghiên cứu chung trong các lĩnh vực mà hai bên cùng có thế mạnh.</p>\n<p style=\"text-align: justify\">Phía IHFC đánh giá cao năng lực đào tạo và nghiên cứu của PTIT trong lĩnh vực viễn thông và công nghệ thông tin tại Việt Nam. Hai bên nhận định tiềm năng hợp tác giữa hệ sinh thái đổi mới sáng tạo của IIT Delhi và PTIT là rất lớn, góp phần hiện thực hóa các cam kết hợp tác về khoa học công nghệ và đổi mới sáng tạo giữa hai quốc gia.</p>\n\n<div id=\"attachment_40692\" class=\"wp-caption aligncenter\">\n    <img class=\"wp-image-40692 size-full\" src=\"/images/post_4/5555.jpg\" alt=\"\" width=\"2048\" height=\"1267\" />\n    <p id=\"caption-attachment-40692\" class=\"wp-caption-text\">Đoàn công tác tham quan phòng thí nghiệm tại IHFC</p>\n</div>\n\n<p style=\"text-align: justify\">Chuyến làm việc của PTIT tại IHFC (IIT Delhi) tiếp tục khẳng định chiến lược chủ động hội nhập quốc tế và khát vọng vươn tầm của Học viện trong việc tiếp cận các mô hình đổi mới sáng tạo tiên tiến trên thế giới, qua đó chuẩn bị nguồn lực chất lượng cao phục vụ chiến lược chuyển đổi số và phát triển kinh tế số của đất nước.</p>','/images/post_4/6666.jpg','Tin tức','2026-05-06','huongbtb'),(5,'PTIT mùa tuyển sinh 2026: Đa dạng chương trình đào tạo, mở rộng cánh cửa hội nhập cho sinh viên','ptit-mua-tuyen-sinh-2026-da-dang-chuong-trinh-dao-tao-mo-rong-canh-cua-hoi-nhap-cho-sinh-vien','Năm 2026, Học viện Công nghệ Bưu chính Viễn thông (PTIT) tiếp tục khẳng định vị thế là cơ sở đào tạo hàng đầu trong lĩnh vực ICT với việc đa dạng hóa các chương trình đào tạo, mở ra nhiều cơ hội hội nhập quốc tế cho sinh viên.','<p style=\"text-align: justify\">Năm 2026, Học viện Công nghệ Bưu chính Viễn thông (PTIT) tiếp tục khẳng định vị thế là cơ sở đào tạo hàng đầu trong lĩnh vực ICT với việc đa dạng hóa các chương trình đào tạo, mở ra nhiều cơ hội hội nhập quốc tế cho sinh viên. Với mục tiêu đào tạo nguồn nhân lực chất lượng cao, sẵn sàng thích ứng với cuộc Cách mạng Công nghiệp 4.0, Học viện đã không ngừng cập nhật và đổi mới chương trình học theo tiêu chuẩn quốc tế.</p>\n<p style=\"text-align: justify\">Điểm nổi bật trong mùa tuyển sinh năm nay là sự xuất hiện của các chương trình liên kết quốc tế và các ngành đào tạo mới đón đầu xu hướng công nghệ. Sinh viên không chỉ được trang bị kiến thức chuyên môn vững chắc mà còn có cơ hội tiếp cận với môi trường học tập hiện đại, sử dụng các công nghệ tiên tiến nhất hiện nay như Trí tuệ nhân tạo (AI), Dữ liệu lớn (Big Data) và Internet vạn vật (IoT).</p>\n\n<div id=\"attachment_40685\" class=\"wp-caption aligncenter\">\n    <img class=\"wp-image-40685 size-full\" src=\"/images/post_5/629339748_1687686815905593_1673711469744017132.jpg\" alt=\"\" width=\"1600\" height=\"900\" />\n    <p id=\"caption-attachment-40685\" class=\"wp-caption-text\">Sinh viên PTIT trong môi trường học tập năng động</p>\n</div>\n\n<p style=\"text-align: justify\">Bên cạnh đó, Học viện cũng đẩy mạnh các hoạt động hợp tác với các tập đoàn công nghệ lớn trong và ngoài nước, tạo điều kiện cho sinh viên thực tập và làm việc ngay từ khi còn ngồi trên ghế nhà trường. Các chương trình học bổng tài năng, hỗ trợ khởi nghiệp và các câu lạc bộ học thuật cũng là những điểm cộng thu hút thí sinh trong kỳ tuyển sinh 2026.</p>\n<p style=\"text-align: justify\">Với phương châm lấy người học làm trung tâm, PTIT cam kết mang đến một môi trường giáo dục toàn diện, giúp sinh viên không chỉ giỏi về kỹ thuật mà còn có tư duy sáng tạo, kỹ năng mềm và khả năng ngoại ngữ xuất sắc để tự tin bước ra thị trường lao động toàn cầu.</p>','/images/post_5/629339748_1687686815905593_1673711469744017132.jpg','Tin tức','2026-05-05','huongbtb'),(6,'PTIT mở chương trình đào tạo Kỹ thuật Truyền thông hàng không vũ trụ: Đón đầu hạ tầng kết nối của tương lai','ptit-mo-chuong-trinh-dao-tao-ky-thuat-truyen-thong-hang-khong-vu-tru-don-dau-ha-tang-ket-noi-cua-tuong-lai','Trong bối cảnh công nghệ không gian, vệ tinh và mạng phi mặt đất đang trở thành một phần quan trọng của hạ tầng số toàn cầu, Học viện Công nghệ Bưu chính Viễn thông (PTIT) chính thức mở chương trình đào tạo \"Kỹ thuật Truyền thông hàng không vũ trụ\" từ năm 2026.','<p style=\"text-align: justify\"><em><strong>T</strong><strong>rong bối cảnh công nghệ không gian, vệ tinh và mạng phi mặt đất đang trở thành một phần quan trọng của hạ tầng số toàn cầu, Học viện Công nghệ Bưu chính Viễn thông (PTIT) chính thức mở chương trình đào tạo “Kỹ thuật Truyền thông hàng không vũ trụ” từ năm 2026. Đây được xem là một trong những ngành học công nghệ chiến lược, đón đầu xu thế phát triển của thế giới trong kỷ nguyên kết nối không gian.</strong></em></p>\n<p style=\"text-align: justify\">Theo PGS.TS Đặng Thế Ngọc, Phó Trưởng khoa phụ trách Khoa Viễn thông 1 Học viện Công nghệ Bưu chính Viễn thông, chương trình đào tạo Kỹ thuật Truyền thông hàng không vũ trụ được xây dựng nhằm đào tạo nguồn nhân lực chất lượng cao trong lĩnh vực truyền thông không gian, vệ tinh, mạng phi mặt đất và các hệ thống kết nối thông minh giữa mặt đất – trên không – không gian. Đây là lĩnh vực còn rất mới tại Việt Nam nhưng đang phát triển mạnh mẽ trên thế giới cùng với sự bùng nổ của Internet vệ tinh, mạng 6G, UAV, đô thị thông minh trên không và công nghệ quan sát Trái Đất.</p>\n<p style=\"text-align: justify\">Theo đề án mở chương trình đào tạo, ngành công nghiệp vũ trụ toàn cầu đang chứng kiến sự tăng trưởng chưa từng có. Chỉ trong vòng 5 năm tới, thế giới dự kiến sẽ triển khai thêm từ 60.000 đến 100.000 vệ tinh mới, chủ yếu là các chòm sao vệ tinh quỹ đạo thấp (LEO) phục vụ Internet băng rộng toàn cầu như Starlink, OneWeb hay Project Kuiper. Sự phát triển này kéo theo nhu cầu rất lớn về đội ngũ kỹ sư có khả năng thiết kế và vận hành các hệ thống truyền thông vệ tinh, mạng không gian, hệ thống định vị – dẫn đường và hạ tầng kết nối tích hợp giữa không gian và mặt đất.</p>\n<p><img class=\"aligncenter size-full\" src=\"/images/post_6/1-2.jpg\" alt=\"\" /></p>\n<p style=\"text-align: center\"><em>PGS.TS Đặng Hoài Bắc- Giám đốc PTIT (bên phải) và PGS.TS. Phạm Anh Tuấn–Tổng Giám đốc VNSC ký thỏa thuận hợp tác trong lĩnh vực thông tin vệ tinh và truyền thông không gian</em></p>\n<p style=\"text-align: justify\">Chương trình “Kỹ thuật Truyền thông hàng không vũ trụ” được PTIT phát triển trên nền tảng thế mạnh truyền thống về viễn thông, công nghệ số và hạ tầng mạng. Sinh viên theo học sẽ được trang bị kiến thức về truyền thông vệ tinh, thông tin vô tuyến, mạng vệ tinh quỹ đạo thấp (LEO), truyền dẫn hàng không, định vị – dẫn đường, mạng phi mặt đất (NTN), công nghệ UAV, truyền thông quang không gian tự do (FSO), an ninh mạng vệ tinh và các hệ thống kết nối tích hợp không gian – mặt đất.</p>\n<p style=\"text-align: justify\">Điểm khác biệt của chương trình nằm ở định hướng liên ngành giữa viễn thông, công nghệ không gian, trí tuệ nhân tạo và tự động hóa. Theo khảo sát trong đề án mở ngành, phần lớn các chương trình hàng không vũ trụ hiện nay tại Việt Nam vẫn thiên về cơ khí, khí động học hoặc bảo dưỡng máy bay; trong khi các nội dung về truyền thông vệ tinh, điện tử hàng không, hệ thống định vị và mạng không gian vẫn còn hạn chế. Vì vậy, chương trình của PTIT được xem là hướng đi mới nhằm lấp đầy khoảng trống chiến lược trong đào tạo nguồn nhân lực công nghệ cao cho lĩnh vực hàng không vũ trụ.</p>\n<p style=\"text-align: justify\">Đề án cũng cho thấy xu hướng đào tạo trên thế giới đang thay đổi mạnh mẽ. Nhiều trường đại học hàng đầu như MIT, Georgia Tech, Cranfield University hay ENAC đã tích hợp sâu các công nghệ truyền thông, hệ thống điện tử hàng không, mạng số và AI vào chương trình đào tạo hàng không vũ trụ. Điều này phản ánh xu hướng chuyển dịch của ngành công nghiệp hàng không vũ trụ toàn cầu từ mô hình cơ khí truyền thống sang các hệ thống kết nối thông minh, tự động hóa và dữ liệu lớn.</p>\n<p style=\"text-align: justify\">Đặc biệt, chương trình được triển khai trong bối cảnh Việt Nam đang thúc đẩy mạnh mẽ phát triển các ngành công nghệ chiến lược, trong đó công nghệ không gian và hạ tầng truyền thông thế hệ mới được xác định là lĩnh vực có vai trò quan trọng đối với chuyển đổi số quốc gia, quốc phòng – an ninh và phát triển kinh tế số.</p>\n<p style=\"text-align: justify\">Trước đó, vào tháng 5/2025, Học viện Công nghệ Bưu chính Viễn thông và Trung tâm Vũ trụ Việt Nam (VNSC) đã ký kết hợp tác trong lĩnh vực thông tin vệ tinh, truyền thông không gian và đào tạo nguồn nhân lực công nghệ cao. Đây được xem là bước đi quan trọng nhằm gắn đào tạo với nghiên cứu, ứng dụng thực tiễn và xu hướng phát triển công nghệ không gian tại Việt Nam.</p>\n<p><img class=\"aligncenter size-full\" src=\"/images/post_6/2-1.jpg\" alt=\"\" /></p>\n<p style=\"text-align: center\"><em>Toàn cảnh buổi làm việc giữa PTIT và VNSC</em></p>\n<p style=\"text-align: justify\">Theo các chuyên gia, trong tương lai gần, hạ tầng kết nối sẽ không chỉ dừng ở mạng mặt đất mà chuyển sang mô hình kết nối đa tầng giữa vệ tinh, máy bay, UAV và các hệ thống thông minh trên không. Điều này kéo theo nhu cầu lớn về nguồn nhân lực am hiểu cả viễn thông, mạng không dây, công nghệ vệ tinh, dữ liệu không gian và hệ thống hàng không số.</p>\n<p style=\"text-align: justify\">Sinh viên tốt nghiệp chương trình có thể làm việc trong các lĩnh vực viễn thông, công nghệ vệ tinh, hàng không, UAV, logistics tầm thấp, quan sát Trái Đất, quốc phòng – an ninh và các trung tâm nghiên cứu phát triển công nghệ cao. Các vị trí nghề nghiệp tiềm năng gồm kỹ sư hệ thống vệ tinh, kỹ sư truyền thông vệ tinh, kỹ sư vận hành vệ tinh, kỹ sư AI/tự động hóa cho hệ thống không gian, kỹ sư robot không gian, chuyên gia an ninh mạng vệ tinh và chuyên gia phân tích dữ liệu viễn thám.</p>\n<p style=\"text-align: justify\">Việc mở chương trình “Kỹ thuật Truyền thông hàng không vũ trụ” tiếp tục cho thấy định hướng của PTIT trong việc tiên phong đào tạo các lĩnh vực công nghệ mới, gắn với chiến lược phát triển quốc gia và nhu cầu nhân lực của tương lai. Không chỉ là một ngành học mới, đây còn là bước chuẩn bị nguồn nhân lực cho kỷ nguyên kết nối không gian – nơi công nghệ viễn thông, trí tuệ nhân tạo, dữ liệu và hàng không hội tụ để hình thành hạ tầng số thế hệ tiếp theo.</p>','/images/post_6/1-2.jpg','Tin tức','2026-05-09','huongbtb'),(7,'Học viện Công nghệ Bưu chính Viễn thông trao học bổng toàn phần cho sinh viên Sri Lanka và tặng ứng dụng hỗ trợ học tiếng Việt','hoc-vien-cong-nghe-buu-chinh-vien-thong-trao-hoc-bong-toan-phan-cho-sinh-vien-sri-lanka-va-tang-ung-dung-ho-tro-hoc-tieng-viet','Chiều ngày 09/5, tại Học viện Công nghệ Bưu chính Viễn thông, PGS.TS Đặng Hoài Bắc, Giám đốc Học viện đã có buổi làm việc với Đoàn công tác của Bộ Khoa học, Công nghệ và Nghiên cứu Sri Lanka dẫn đầu bởi ông Deepa Liyanage, Thứ trưởng phụ trách Khoa học và Công nghệ.','<p style=\"text-align: justify\"><em><strong>Chiều ngày 09/5, tại Học viện Công nghệ Bưu chính Viễn thông, PGS.TS Đặng Hoài Bắc, Giám đốc Học viện đã có buổi làm việc với Đoàn công tác của Bộ Khoa học, Công nghệ và Nghiên cứu Sri Lanka dẫn đầu bởi ông Deepa Liyanage, Thứ trưởng phụ trách Khoa học và Công nghệ. Tại buổi làm việc, Học viện đã trao tặng học bổng toàn phần cho sinh viên Sri Lanka và bàn giao ứng dụng hỗ trợ học tiếng Việt.</strong></em></p>\n<p style=\"text-align: justify\">Phát biểu tại buổi làm việc, PGS.TS Đặng Hoài Bắc hoan nghênh đoàn công tác Sri Lanka đã đến thăm và làm việc tại Học viện. Ông nhấn mạnh, PTIT luôn coi trọng việc hợp tác quốc tế, đặc biệt là với các quốc gia trong khu vực Nam Á. Việc trao học bổng cho sinh viên Sri Lanka là minh chứng cho nỗ lực của Học viện trong việc thúc đẩy giao lưu văn hóa và giáo dục giữa hai nước.</p>\n\n<div class=\"wp-caption aligncenter\">\n    <img class=\"size-full\" src=\"/images/post_7/3105555554875011543.jpg\" alt=\"Trao học bổng cho sinh viên Sri Lanka\" />\n    <p class=\"wp-caption-text\">PGS.TS Đặng Hoài Bắc trao học bổng toàn phần cho đại diện Sri Lanka</p>\n</div>\n\n<p style=\"text-align: justify\">Đặc biệt, trong dịp này, Học viện cũng đã trao tặng phía Sri Lanka ứng dụng hỗ trợ học tiếng Việt do các giảng viên và sinh viên Học viện nghiên cứu, phát triển. Đây là công cụ hữu ích giúp người dân Sri Lanka, đặc biệt là các bạn sinh viên có ý định sang Việt Nam du học, có thể tiếp cận và học ngôn ngữ một cách dễ dàng và hiệu quả hơn.</p>\n\n<div class=\"wp-caption aligncenter\">\n    <img class=\"size-full\" src=\"/images/post_7/21111111111.jpg\" alt=\"Đoàn công tác chụp ảnh lưu niệm\" />\n    <p class=\"wp-caption-text\">Đoàn công tác Bộ Khoa học, Công nghệ và Nghiên cứu Sri Lanka chụp ảnh lưu niệm cùng lãnh đạo Học viện</p>\n</div>\n\n<p style=\"text-align: justify\">Ông Deepa Liyanage, Thứ trưởng phụ trách Khoa học và Công nghệ Sri Lanka bày tỏ sự trân trọng đối với những hỗ trợ quý báu từ phía Học viện. Ông tin tưởng rằng, những thỏa thuận hợp tác này sẽ là khởi đầu tốt đẹp cho mối quan hệ bền chặt giữa Bộ Khoa học, Công nghệ và Nghiên cứu Sri Lanka và Học viện Công nghệ Bưu chính Viễn thông trong tương lai, góp phần thúc đẩy sự phát triển khoa học công nghệ của cả hai bên.</p>','/images/post_7/3105555554875011543.jpg','Tin tức','2026-05-09','huongbtb'),(8,'PTIT 2026: Chính sách học bổng “khủng” – chiến lược dài hạn thu hút và nuôi dưỡng nhân tài công nghệ','ptit-2026-chinh-sach-hoc-bong-khung-chien-luoc-dai-han-thu-hut-va-nuoi-duong-nhan-tai-cong-nghe','Tiếp nối định hướng thu hút, bồi dưỡng và trọng dụng nhân tài đã được triển khai từ năm 2024, năm học 2026, Học viện Công nghệ Bưu chính Viễn thông (PTIT) tiếp tục công bố chính sách học bổng với nhiều ưu đãi vượt trội, đa dạng và ngày càng hoàn thiện.','<p style=\"text-align: justify\"><em><strong>Tiếp nối định hướng thu hút, bồi dưỡng và trọng dụng nhân tài đã được triển khai từ năm 2024, năm học 2026, Học viện Công nghệ Bưu chính Viễn thông (PTIT) tiếp tục công bố chính sách học bổng với nhiều ưu đãi vượt trội, đa dạng và ngày càng hoàn thiện. Đây không chỉ là chính sách hỗ trợ tài chính, mà là một chiến lược dài hạn nhằm phát hiện sớm, đầu tư có trọng điểm và phát triển toàn diện nguồn nhân lực chất lượng cao ngay từ bậc đại học.</strong></em></p>\n<p style=\"text-align: justify\"><strong>Học bổng 500 triệu đồng: Bệ phóng cho tài năng đỉnh cao</strong></p>\n<p style=\"text-align: justify\">Nổi bật trong chính sách năm 2026 là chương trình Học bổng đặc biệt với tối đa 30 suất, trị giá lên tới 500 triệu đồng mỗi suất. Học bổng bao gồm toàn bộ học phí, hỗ trợ chi phí sinh hoạt, kinh phí nghiên cứu khoa học, thực tập quốc tế cùng nhiều cơ hội phát triển từ mạng lưới doanh nghiệp đối tác.</p>\n<p style=\"text-align: justify\">Đối tượng xét cấp là các thí sinh thuộc nhóm xuất sắc nhất như: tham dự đội tuyển Olympic quốc tế; đạt giải Nhất, Nhì, Ba học sinh giỏi quốc gia các môn Toán, Vật lí, Tin học; hoặc đạt từ 29,0 điểm trở lên trong kỳ thi tốt nghiệp THPT. Sinh viên nhận học bổng cần duy trì kết quả học tập loại Giỏi trong suốt quá trình đào tạo.</p>\n<p style=\"text-align: justify\"><img class=\"aligncenter size-full\" src=\"/images/post_8/2.avif\" alt=\"\" /></p>\n<p style=\"text-align: justify\"><strong>Hiệu quả đã được kiểm chứng: Dấu ấn từ các khóa sinh viên tài năng</strong></p>\n<p style=\"text-align: justify\">Chính sách học bổng tài năng của PTIT, triển khai từ năm 2024, đã bước đầu cho thấy hiệu quả rõ nét. Đặc biệt, năm 2025, Học viện đã tuyển chọn và trao học bổng cho 9 sinh viên xuất sắc – những gương mặt tiêu biểu không chỉ có nền tảng học thuật vững chắc mà còn thể hiện năng lực vượt trội trong môi trường đại học.</p>\n<p style=\"text-align: justify\">Trong quá trình học tập, các sinh viên này liên tục đạt thành tích cao tại các sân chơi học thuật uy tín như Olympic Tin học Sinh viên toàn quốc, Olympic AI Sinh viên toàn quốc… Nhiều em đã được cọ xát tại các cuộc thi, hội thảo và chương trình học thuật quốc tế tại Hàn Quốc, Đài Loan, Indonesia…, qua đó nâng cao năng lực nghiên cứu và hội nhập toàn cầu.</p>\n<p style=\"text-align: justify\">(Thông tin chi tiết về các gương mặt sinh viên tài năng có thể tham khảo tại chuyên trang: tainang.ptit.edu.vn)</p>\n<p style=\"text-align: justify\"><img class=\"aligncenter size-full\" src=\"/images/post_8/3.avif\" alt=\"\" /></p>\n<p style=\"text-align: center\"><em>Đội tuyển PTIT.Star và thầy Nguyễn Mạnh Sơn</em></p>\n<p style=\"text-align: justify\"><strong>Từ học bổng đến lộ trình tinh hoa: Cơ hội học thẳng thạc sĩ trong 5 năm</strong></p>\n<p style=\"text-align: justify\">Điểm mới đáng chú ý từ năm 2026 là chính sách học bổng không chỉ dừng lại ở hỗ trợ tài chính mà còn trở thành <strong>đòn bẩy học thuật</strong> cho sinh viên tài năng. Cụ thể, các sinh viên thuộc diện học bổng có cơ hội tham gia <strong>chương trình đào tạo tài năng tích hợp cử nhân – thạc sĩ</strong>, cho phép hoàn thành đồng thời hai bằng trong lộ trình khoảng 5 năm.</p>\n<p style=\"text-align: justify\">Theo định hướng đào tạo mới, PTIT triển khai 5 chương trình thạc sĩ tích hợp, thiết kế riêng cho nhóm sinh viên có năng lực vượt trội, giúp rút ngắn thời gian đào tạo, tăng cường nghiên cứu chuyên sâu và sớm tiếp cận các vị trí công việc chất lượng cao. Đây được xem là bước đi chiến lược nhằm hình thành đội ngũ nhân lực tinh hoa, có khả năng dẫn dắt trong các lĩnh vực công nghệ mũi nhọn.</p>\n<p style=\"text-align: justify\">Như vậy, học bổng không chỉ là phần thưởng đầu vào, mà còn là <strong>cánh cửa mở ra một lộ trình phát triển vượt trội</strong>, nơi sinh viên được đầu tư liên tục từ đại học đến sau đại học trong một hệ sinh thái đào tạo đồng bộ.</p>\n<p style=\"text-align: justify\"><img class=\"aligncenter size-full\" src=\"/images/post_8/1.jpg\" alt=\"\" /></p>\n<p style=\"text-align: justify\"><strong>Đa dạng các gói học bổng: Mở rộng cơ hội cho nhiều đối tượng</strong></p>\n<p style=\"text-align: justify\">Bên cạnh học bổng đặc biệt, PTIT tiếp tục triển khai các gói học bổng toàn phần và bán phần:</p>\n<ul style=\"text-align: justify\">\n<li>Tối đa 50 suất học bổng toàn phần trị giá tới 250 triệu đồng/suất</li>\n<li>Tối đa 50 suất học bổng bán phần trị giá tới 100 triệu đồng/suất</li>\n</ul>\n<p style=\"text-align: justify\">Dành cho các thí sinh đạt giải học sinh giỏi quốc gia, cấp tỉnh/thành phố hoặc có điểm thi tốt nghiệp THPT từ 28,0 – 28,5 điểm trở lên.</p>\n<p style=\"text-align: justify\"><strong>Học bổng diện rộng: Không để tài năng bị bỏ lỡ</strong></p>\n<p style=\"text-align: justify\">Song song với các chương trình trọng điểm, Học viện tiếp tục triển khai:</p>\n<ul style=\"text-align: justify\">\n<li>100 suất miễn 100% học phí năm thứ nhất</li>\n<li>300 suất miễn 50% học phí năm thứ nhất</li>\n</ul>\n<p style=\"text-align: justify\">Nhằm tạo cơ hội cho nhiều học sinh giỏi tiếp cận môi trường đào tạo chất lượng cao.</p>\n<p style=\"text-align: justify\"><strong>Kết nối doanh nghiệp – mở rộng cơ hội toàn cầu</strong></p>\n<p style=\"text-align: justify\">Chính sách học bổng của PTIT còn có sự đồng hành của nhiều tập đoàn, tổ chức quốc tế như Samsung, Cowell Asia, Yokogawa, Đại học Sydney, TEMIX, Bosch… mang đến cơ hội thực tập, trải nghiệm môi trường làm việc toàn cầu và phát triển nghề nghiệp.</p>\n<p style=\"text-align: justify\"><img class=\"aligncenter size-full\" src=\"/images/post_8/5.avif\" alt=\"\" /></p>\n<p style=\"text-align: center\"><em style=\"text-align: center\">7 sinh viên xuất sắc nhận Học bổng Tài năng Samsung (Samsung Talent Program – STP) 2025 trị giá 3000 USD/sinh viên (khoảng 80 triệu đồng)</em></p>\n<p style=\"text-align: justify\"><strong>Chiến lược dài hạn cho nguồn nhân lực chất lượng cao</strong><em style=\"text-align: center\"> </em></p>\n<p style=\"text-align: justify\">Theo quy định, mỗi thí sinh chỉ được xét và cấp một loại học bổng cao nhất theo nguyên tắc từ cao xuống thấp cho đến khi hết chỉ tiêu.</p>\n<p style=\"text-align: justify\">Với việc triển khai liên tục từ năm 2024 và mở rộng chiều sâu từ năm 2026 với các chương trình đào tạo tích hợp, chính sách học bổng của PTIT không chỉ là hỗ trợ tài chính mà đã trở thành <strong>hệ sinh thái phát triển nhân tài toàn diện</strong> – nơi sinh viên giỏi được phát hiện sớm, đầu tư bài bản và bứt phá trên lộ trình học thuật – nghề nghiệp mang tầm quốc tế.</p>','/images/post_8/thumbnail.jpg','Tin tức','2026-05-04','huongbtb'),(9,'Hàng ngàn sinh viên hào hứng với các khóa đào tạo kỹ năng mềm và đổi mới sáng tạo tại Hòa Lạc','hang-ngan-sinh-vien-hao-hung-voi-cac-khoa-dao-tao-ky-nang-mem-va-doi-moi-sang-tao-tai-hoa-lac','Nhằm trang bị cho sinh viên tư duy đổi mới sáng tạo, năng lực khởi nghiệp và bộ kỹ năng mềm thiết yếu như làm việc nhóm, giao tiếp, giải quyết vấn đề và thích ứng với môi trường làm việc thực tế, Học viện Công nghệ Bưu chính Viễn thông (PTIT) đã triển khai...','<p style=\"text-align: justify\"><em><strong>Nhằm trang bị cho sinh viên tư duy đổi mới sáng tạo, năng lực khởi nghiệp và bộ kỹ năng mềm thiết yếu như làm việc nhóm, giao tiếp, giải quyết vấn đề và thích ứng với môi trường làm việc thực tế, Học viện Công nghệ Bưu chính Viễn thông (PTIT) đã triển khai chương trình đào tạo ngoại khóa “Kỹ năng mềm và kiến thức khởi nghiệp, đổi mới sáng tạo” dành cho sinh viên tại Cơ sở Hòa Lạc của Học viện. Các khóa đào tạo này cũng được kỳ vọng sẽ thu hẹp khoảng cách giữa đào tạo trong nhà trường và yêu cầu của doanh nghiệp trong kỷ nguyên số. Sau 4 tuần triển khai, chương trình bước đầu ghi nhận những kết quả tích cực, góp phần nâng cao năng lực thực tiễn và khả năng thích ứng của sinh viên trong bối cảnh chuyển đổi số.</strong></em></p>\n\n<div id=\"attachment_40629\" class=\"wp-caption aligncenter\">\n    <img class=\"wp-image-40629 size-full\" src=\"/images/post_9/10.png\" alt=\"\" />\n    <p id=\"caption-attachment-40629\" class=\"wp-caption-text\">Sinh viên PTIT trong buổi học ngoại khóa “Kỹ năng mềm và kiến thức khởi nghiệp, đổi mới sáng tạo”</p>\n</div>\n\n<p style=\"text-align: justify\">Trong bối cảnh hệ sinh thái đổi mới sáng tạo ngày càng gắn chặt với doanh nghiệp và thị trường, yêu cầu đối với sinh viên không chỉ dừng ở khả năng tiếp thu kiến thức mà còn ở năng lực triển khai ý tưởng thành sản phẩm, mô hình kinh doanh cụ thể. Thực tiễn cho thấy, trải nghiệm môi trường làm việc, va chạm với các bài toán thực tế và hiểu cách vận hành của doanh nghiệp công nghệ là yếu tố quan trọng giúp sinh viên định hình rõ hơn lộ trình nghề nghiệp và tư duy phát triển dài hạn.</p>\n\n<p style=\"text-align: justify\">Trên cơ sở đó, các đào tạo ngoại khóa “Kỹ năng mềm và kiến thức khởi nghiệp, đổi mới sáng tạo” tại Khu Công nghệ cao Hòa Lạc như một không gian học tập mở, tăng cường kết nối giữa sinh viên với chuyên gia, doanh nghiệp và các mô hình khởi nghiệp thực tế, qua đó thúc đẩy tinh thần chủ động, sáng tạo và khả năng thử nghiệm ý tưởng trong môi trường gần với thực tiễn.</p>\n\n<div id=\"attachment_40631\" class=\"wp-caption aligncenter\">\n    <img class=\"wp-image-40631 size-full\" src=\"/images/post_9/5.png\" alt=\"\" />\n    <p id=\"caption-attachment-40631\" class=\"wp-caption-text\">Sinh viên PTIT tham gia lớp “Kỹ năng thuyết trình hiệu quả”</p>\n</div>\n\n<p style=\"text-align: justify\">Hiện nay, chương trình đã hoàn thành các nội dung đào tạo nền tảng, thu hút hơn 1.000 sinh viên Học viện tham gia và bước đầu ghi nhận những chuyển biến tích cực. Với vai trò là các học phần bổ trợ cho chương trình đào tạo chính quy, chương trình góp phần tăng cường khả năng vận dụng kiến thức vào thực tiễn và hỗ trợ định hướng phát triển toàn diện cho sinh viên.</p>\n\n<p style=\"text-align: justify\">Thông qua mô hình học tập gắn với trải nghiệm và thực hành, sinh viên không chỉ cải thiện kỹ năng giao tiếp, trình bày ý tưởng mà còn nâng cao khả năng làm việc nhóm và xử lý tình huống. Đáng chú ý, nhiều sinh viên đã thể hiện sự tiến bộ trong tư duy phản biện, cách tiếp cận vấn đề có hệ thống và khả năng xây dựng, phát triển ý tưởng theo hướng khả thi hơn.</p>\n\n<p style=\"text-align: justify\">Bên cạnh đó, chương trình còn góp phần định hình tác phong học tập chuyên nghiệp, khuyến khích tinh thần chủ động và trách nhiệm cá nhân trong quá trình học tập. Việc tiếp cận các bài toán gắn với thực tiễn cũng giúp sinh viên từng bước làm quen với môi trường làm việc, tạo tiền đề quan trọng để thích ứng tốt hơn với yêu cầu của thị trường lao động trong giai đoạn chuyển đổi số.</p>\n\n<div id=\"attachment_40630\" class=\"wp-caption aligncenter\">\n    <img class=\"wp-image-40630 size-full\" src=\"/images/post_9/8.png\" alt=\"\" />\n    <p id=\"caption-attachment-40630\" class=\"wp-caption-text\">Bài tập thực hành trong chuyên đề “Kỹ năng thuyết trình hiệu quả”</p>\n</div>','/images/post_9/5.png','Tin tức','2026-04-29','huongbtb'),(10,'Viện Lãnh đạo, Quản trị và Quản lý Việt Nam chính thức xây dựng và triển khai chương trình CEO Mentoring – Nâng tầm tư duy, bứt phá tăng trưởng','vien-lanh-dao-quan-tri-va-quan-ly-viet-nam-chinh-thuc-xay-dung-va-trien-khai-chuong-trinh-ceo-mentoring-nang-tam-tu-duy-but-pha-tang-truong','Sáng ngày 22/4, tại Hà Nội, Viện Lãnh đạo, Quản trị và Quản lý Việt Nam (VML) đã tổ chức Lễ khởi động và giới thiệu chương trình đào tạo “CEO Mentoring – Nâng tầm tư duy, bứt phá tăng trưởng” dành cho các cấp quản lý, lãnh đạo của Học viện.','<p style=\"text-align: justify\"><em><strong>Sáng ngày 22/4, tại Hà Nội, Viện Lãnh đạo, Quản trị và Quản lý Việt Nam (VML) đã tổ chức Lễ khởi động và giới thiệu chương trình đào tạo “CEO Mentoring – Nâng tầm tư duy, bứt phá tăng trưởng” dành cho các cấp quản lý, lãnh đạo của Học viện. </strong></em></p>\n\n<div id=\"attachment_40578\" class=\"wp-caption aligncenter\">\n    <img class=\"wp-image-40578 size-full\" src=\"/images/post_10/3.png\" alt=\"TS. Nguyễn Mạnh Sơn phát biểu\" />\n    <p id=\"caption-attachment-40578\" class=\"wp-caption-text\">TS. Nguyễn Mạnh Sơn – Viện trưởng Viện VML phát biểu khai mạc và giới thiệu về mục tiêu, ý nghĩa của chương trình</p>\n</div>\n\n<p style=\"text-align: justify\">Chương trình “CEO Mentoring” được xây dựng trên cơ sở nhu cầu thực tiễn nhằm hỗ trợ, đồng hành cùng đội ngũ lãnh đạo, quản lý của Học viện trong việc cập nhật kiến thức, kỹ năng quản trị hiện đại, đồng thời thúc đẩy tư duy đổi mới sáng tạo và khả năng thích ứng với những thay đổi nhanh chóng của môi trường giáo dục đại học trong kỷ nguyên số.</p>\n\n<p style=\"text-align: justify\">Điểm đặc biệt của chương trình là mô hình Mentoring (Cố vấn), nơi các học viên sẽ được dẫn dắt, chia sẻ kinh nghiệm trực tiếp từ các Mentor là những nhà lãnh đạo, chuyên gia uy tín, có bề dày kinh nghiệm thực chiến trong công tác quản trị và điều hành doanh nghiệp, tổ chức.</p>\n\n<div id=\"attachment_40579\" class=\"wp-caption aligncenter\">\n    <img class=\"wp-image-40579 size-full\" src=\"/images/post_10/4.png\" alt=\"Toàn cảnh Lễ khởi động\" />\n    <p id=\"caption-attachment-40579\" class=\"wp-caption-text\">Toàn cảnh Lễ khởi động chương trình CEO Mentoring</p>\n</div>\n\n<p style=\"text-align: justify\">Tại buổi lễ, các đại biểu và học viên đã cùng trao đổi về vai trò của công tác đào tạo cán bộ lãnh đạo, quản lý trong chiến lược phát triển bền vững của Học viện. Viện VML kỳ vọng, thông qua chương trình này, các học viên sẽ không chỉ được trang bị những công cụ quản trị hữu hiệu mà còn hình thành được mạng lưới kết nối, chia sẻ tri thức giữa các cấp quản lý.</p>\n\n<div id=\"attachment_40580\" class=\"wp-caption aligncenter\">\n    <img class=\"wp-image-40580 size-full\" src=\"/images/post_10/1.png\" alt=\"Lãnh đạo Học viện tặng hoa\" />\n    <p id=\"caption-attachment-40580\" class=\"wp-caption-text\">Lãnh đạo Học viện tặng hoa chúc mừng Ban tổ chức chương trình</p>\n</div>\n\n<p style=\"text-align: justify\">Việc chính thức xây dựng và triển khai chương trình CEO Mentoring là một trong những hoạt động trọng tâm của Viện VML trong năm 2026, góp phần hiện thực hóa mục tiêu nâng cao chất lượng nguồn nhân lực quản lý, đáp ứng yêu cầu chuyển đổi số và phát triển Học viện trong giai đoạn mới.</p>','/images/post_10/3.png','Tin tức','2026-04-22','huongbtb'),(11,'PTIT long trọng tổ chức Lễ Khai giảng năm học 2025 – 2026 và chào đón gần 7.000 tân sinh viên','ptit-long-trong-to-chuc-le-khai-giang-nam-hoc-2025-2026-va-chao-don-gan-7000-tan-sinh-vien','Sáng ngày 24/10, Học viện Công nghệ Bưu chính Viễn thông (PTIT) đã long trọng tổ chức Lễ Khai giảng năm học 2025 – 2026 và chào đón gần 7.000 tân sinh viên khóa 2025 nhập học.','<p style=\"text-align: justify\"><em><strong>Sáng ngày 24/10, Học viện Công nghệ Bưu chính Viễn thông (PTIT) đã long trọng tổ chức Lễ Khai giảng năm học 2025 – 2026 và chào đón gần 7.000 tân sinh viên khóa 2025 chính thức gia nhập ngôi nhà chung PTIT. Buổi lễ đánh dấu sự khởi đầu của một hành trình học tập mới đầy hứa hẹn trong kỷ nguyên số.</strong></em></p>\n\n<div id=\"attachment_40629\" class=\"wp-caption aligncenter\">\n    <img class=\"wp-image-40629 size-full\" src=\"/images/post_11/1.jpg\" alt=\"\" />\n    <p id=\"caption-attachment-40629\" class=\"wp-caption-text\">Toàn cảnh Lễ Khai giảng năm học 2025 – 2026 của Học viện Công nghệ Bưu chính Viễn thông</p>\n</div>\n\n<p style=\"text-align: justify\">Tham dự buổi lễ có đại diện lãnh đạo Bộ Thông tin và Truyền thông, Bộ Giáo dục và Đào tạo, các đối tác doanh nghiệp trong và ngoài nước, cùng toàn thể Ban Giám đốc Học viện, cán bộ giảng viên và đại diện tân sinh viên tiêu biểu. Lễ khai giảng năm nay không chỉ là sự kiện truyền thống mà còn là dịp để Học viện khẳng định vị thế và tầm nhìn trong việc đào tạo nguồn nhân lực chất lượng cao phục vụ chiến lược chuyển đổi số quốc gia.</p>\n\n<div id=\"attachment_40631\" class=\"wp-caption aligncenter\">\n    <img class=\"wp-image-40631 size-full\" src=\"/images/post_11/2.jpg\" alt=\"\" />\n    <p id=\"caption-attachment-40631\" class=\"wp-caption-text\">PGS.TS Đặng Hoài Bắc – Giám đốc Học viện thực hiện nghi thức đánh trống khai giảng năm học mới</p>\n</div>\n\n<p style=\"text-align: justify\">Phát biểu tại buổi lễ, lãnh đạo Học viện đã chúc mừng và chào đón các tân sinh viên khóa 2025. Học viện cam kết sẽ không ngừng đổi mới phương pháp giảng dạy, đầu tư cơ sở vật chất hiện đại và tạo dựng môi trường học tập sáng tạo nhất để các em có thể phát huy tối đa năng lực bản thân, sẵn sàng thích ứng với những thay đổi nhanh chóng của công nghệ toàn cầu.</p>\n\n<div id=\"attachment_40630\" class=\"wp-caption aligncenter\">\n    <img class=\"wp-image-40630 size-full\" src=\"/images/post_11/3.jpg\" alt=\"\" />\n    <p id=\"caption-attachment-40630\" class=\"wp-caption-text\">Học viện vinh danh và trao học bổng cho các tân sinh viên có thành tích xuất sắc trong kỳ tuyển sinh vừa qua</p>\n</div>\n\n<p style=\"text-align: justify\">Tại buổi lễ, Học viện cũng đã tổ chức vinh danh các Thủ khoa, Á khoa và những sinh viên nhận được học bổng tài năng từ các đối tác chiến lược. Đây là nguồn động viên tinh thần to lớn để các tân sinh viên vững bước trên con đường chinh phục tri thức sắp tới.</p>\n\n<div id=\"attachment_40632\" class=\"wp-caption aligncenter\">\n    <img class=\"wp-image-40632 size-full\" src=\"/images/post_11/4.jpg\" alt=\"\" />\n    <p id=\"caption-attachment-40632\" class=\"wp-caption-text\">Niềm vui và sự hào hứng của các tân sinh viên trong ngày khai trường</p>\n</div>\n\n<p style=\"text-align: justify\">Lễ Khai giảng năm học 2025 – 2026 đã khép lại trong không khí hân hoan và đầy tự hào, mở ra một năm học mới với nhiều khát vọng và quyết tâm vươn tới những đỉnh cao mới trong đào tạo và nghiên cứu khoa học của thầy và trò Học viện.</p>','/images/post_11/1.jpg','Sự kiện','25/10/2025',NULL),(12,'Đại hội Đảng bộ Học viện Công nghệ Bưu chính Viễn thông lần thứ VII, nhiệm kỳ 2025 - 2030','dai-hoi-dang-bo-hoc-vien-cong-nghe-buu-chinh-vien-thong-lan-thu-vii-nhiem-ky-2025-2030','Trong không khí phấn khởi của những ngày tháng 5 lịch sử, Đảng bộ Học viện Công nghệ Bưu chính Viễn thông đã long trọng tổ chức Đại hội lần thứ VII, nhiệm kỳ 2025 – 2030.','<p style=\"text-align: justify\"><em><strong>Trong không khí phấn khởi của những ngày tháng 5 lịch sử, Đảng bộ Học viện Công nghệ Bưu chính Viễn thông đã long trọng tổ chức Đại hội lần thứ VII, nhiệm kỳ 2025 – 2030. Đây là sự kiện chính trị quan trọng, định hình con đường phát triển của Học viện trong giai đoạn 5 năm tới với khát vọng vươn tầm quốc tế.</strong></em></p>\n\n<div class=\"wp-caption aligncenter\">\n    <img class=\"size-full\" src=\"/images/post_12/1.jpg\" alt=\"Toàn cảnh Đại hội\" />\n    <p class=\"wp-caption-text\">Toàn cảnh Đại hội Đảng bộ Học viện Công nghệ Bưu chính Viễn thông lần thứ VII</p>\n</div>\n\n<p style=\"text-align: justify\">Đại hội có sự tham dự của các đại biểu đại diện Đảng ủy cấp trên, cùng đông đảo đảng viên tiêu biểu đến từ các chi bộ trực thuộc Đảng bộ Học viện. Tại Đại hội, các đại biểu đã tập trung thảo luận, đánh giá khách quan, toàn diện những kết quả đạt được trong nhiệm kỳ qua, đồng thời chỉ ra những hạn chế, nguyên nhân và bài học kinh nghiệm.</p>\n\n<div class=\"wp-caption aligncenter\">\n    <img class=\"size-full\" src=\"/images/post_12/2.jpg\" alt=\"Lãnh đạo phát biểu chỉ đạo\" />\n    <p class=\"wp-caption-text\">Đại biểu cấp trên phát biểu chỉ đạo tại Đại hội</p>\n</div>\n\n<p style=\"text-align: justify\">Nhiệm kỳ 2020 – 2025 ghi dấu ấn với những bước phát triển đột phá của Học viện trong công tác đào tạo, nghiên cứu khoa học và chuyển đổi số. Phát huy những thành tựu đó, mục tiêu của nhiệm kỳ 2025 – 2030 là xây dựng Đảng bộ Học viện trong sạch, vững mạnh; tiếp tục đổi mới sáng tạo, nâng cao chất lượng nguồn nhân lực và khẳng định vị thế là trung tâm đào tạo, nghiên cứu hàng đầu về ICT.</p>\n\n<div class=\"wp-caption aligncenter\">\n    <img class=\"size-full\" src=\"/images/post_12/3.jpg\" alt=\"Các đại biểu bỏ phiếu\" />\n    <p class=\"wp-caption-text\">Các đại biểu thực hiện nghi thức bỏ phiếu bầu Ban Chấp hành nhiệm kỳ mới</p>\n</div>\n\n<p style=\"text-align: justify\">Với tinh thần dân chủ và trách nhiệm cao, Đại hội đã bầu ra Ban Chấp hành Đảng bộ Học viện lần thứ VII, nhiệm kỳ 2025 – 2030 gồm những đồng chí có đủ tiêu chuẩn về phẩm chất chính trị, đạo đức và năng lực để lãnh đạo Học viện hoàn thành các mục tiêu chiến lược đã đề ra.</p>\n\n<div class=\"wp-caption aligncenter\">\n    <img class=\"size-full\" src=\"/images/post_12/4.jpg\" alt=\"Ban chấp hành mới ra mắt\" />\n    <p class=\"wp-caption-text\">Ban Chấp hành Đảng bộ Học viện nhiệm kỳ 2025 – 2030 ra mắt Đại hội</p>\n</div>\n\n<p style=\"text-align: justify\">Thành công của Đại hội Đảng bộ Học viện lần thứ VII là nguồn cổ vũ, động viên to lớn đối với toàn thể cán bộ, giảng viên và sinh viên, tạo sự thống nhất về ý chí và hành động để đưa Học viện Công nghệ Bưu chính Viễn thông phát triển bền vững và mạnh mẽ hơn nữa trong tương lai.</p>','/images/post_12/1.jpg','Sự kiện','15/05/2025',NULL),(13,'Ra mắt Trung tâm Công nghệ chiến lược Úc – Việt và công bố tài trợ 8 dự án tiềm năng','ra-mat-trung-tam-cong-nghe-chien-luoc-uc-viet-va-cong-bo-tai-tro-8-du-an-tiem-nang','Sáng ngày 10/5, tại Hà Nội, Học viện Công nghệ Bưu chính Viễn thông phối hợp cùng Đại học Sydney (Úc) chính thức ra mắt Trung tâm Công nghệ chiến lược Úc – Việt (VICATS) và công bố danh sách 8 dự án nghiên cứu tiềm năng nhận tài trợ.','<p style=\"text-align: justify\"><em><strong>Sáng ngày 10/5, tại Hà Nội, Học viện Công nghệ Bưu chính Viễn thông phối hợp cùng Đại học Sydney (Úc) chính thức ra mắt Trung tâm Công nghệ chiến lược Úc – Việt (VICATS) và công bố danh sách 8 dự án nghiên cứu tiềm năng được nhận tài trợ trong giai đoạn 1. Đây là dấu mốc quan trọng trong quan hệ hợp tác về khoa học, công nghệ và đổi mới sáng tạo giữa hai quốc gia.</strong></em></p>\n\n<div class=\"wp-caption aligncenter\">\n    <img class=\"size-full\" src=\"/images/post_13/1.jpg\" alt=\"Lễ ra mắt Trung tâm VICATS\" />\n    <p class=\"wp-caption-text\">Nghi thức ra mắt Trung tâm Công nghệ chiến lược Úc – Việt (VICATS)</p>\n</div>\n\n<p style=\"text-align: justify\">VICATS được thành lập với mục tiêu trở thành cầu nối thúc đẩy các hoạt động nghiên cứu chung, chuyển giao công nghệ và đào tạo nguồn nhân lực chất lượng cao trong các lĩnh vực công nghệ mới như Trí tuệ nhân tạo (AI), Internet vạn vật (IoT), và Công nghệ năng lượng xanh. Trung tâm cũng sẽ tập trung vào việc hỗ trợ hệ sinh thái khởi nghiệp sáng tạo và kết nối các nhà khoa học, doanh nghiệp của hai nước Việt Nam và Úc.</p>\n\n<div class=\"wp-caption aligncenter\">\n    <img class=\"size-full\" src=\"/images/post_13/2.jpg\" alt=\"Trao chứng nhận tài trợ dự án\" />\n    <p class=\"wp-caption-text\">Đại diện Ban tổ chức trao chứng nhận tài trợ cho các dự án nghiên cứu tiềm năng</p>\n</div>\n\n<p style=\"text-align: justify\">Trong khuôn khổ buổi lễ, Ban điều hành Trung tâm cũng đã công bố 8 dự án nghiên cứu xuất sắc được lựa chọn từ hàng chục hồ sơ đăng ký để nhận tài trợ đợt này. Các dự án tập trung vào việc giải quyết các bài toán cấp thiết trong thực tiễn như: giám sát môi trường thông minh, ứng dụng AI trong y tế từ xa, và phát triển vật liệu mới cho pin năng lượng. Mỗi dự án không chỉ có giá trị về mặt học thuật mà còn có tiềm năng ứng dụng và thương mại hóa cao.</p>\n\n<div class=\"wp-caption aligncenter\">\n    <img class=\"size-full\" src=\"/images/post_13/3.jpg\" alt=\"Đại biểu phát biểu\" />\n    <p class=\"wp-caption-text\">Đại diện Đại học Sydney phát biểu về định hướng hợp tác nghiên cứu</p>\n</div>\n\n<p style=\"text-align: justify\">Sự ra đời của VICATS cùng việc công bố các dự án tài trợ khẳng định cam kết mạnh mẽ của Học viện Công nghệ Bưu chính Viễn thông trong việc hội nhập quốc tế và thúc đẩy đổi mới sáng tạo. Đây sẽ là bệ phóng quan trọng để các nhà khoa học Việt Nam tiếp cận với môi trường nghiên cứu hàng đầu thế giới và đóng góp vào sự phát triển bền vững của nền khoa học công nghệ nước nhà.</p>\n\n<div class=\"wp-caption aligncenter\">\n    <img class=\"size-full\" src=\"/images/post_13/4.jpg\" alt=\"Chụp ảnh lưu niệm\" />\n    <p class=\"wp-caption-text\">Đại diện các đơn vị và các nhà khoa học chụp ảnh lưu niệm tại buổi lễ</p>\n</div>','/images/post_13/1.jpg','Sự kiện','10/05/2025',NULL),(14,'PTIT tổ chức Lễ tốt nghiệp cho gần 1000 Kỹ sư, Thạc sỹ, Tiến sỹ','ptit-to-chuc-le-tot-nghiep-cho-gan-1000-ky-su-thac-sy-tien-sy','Sáng ngày 10/4, Học viện Công nghệ Bưu chính Viễn thông (PTIT) đã trang trọng tổ chức Lễ tốt nghiệp và trao bằng đợt 1 năm 2026 cho gần 1.000 tân Tiến sỹ, Thạc sỹ và Kỹ sư.','<p style=\"text-align: justify\"><em><strong>Sáng ngày 10/4, Học viện Công nghệ Bưu chính Viễn thông (PTIT) đã trang trọng tổ chức Lễ tốt nghiệp và trao bằng đợt 1 năm 2026 cho gần 1.000 tân Tiến sỹ, Thạc sỹ và Kỹ sư. Buổi lễ là dấu mốc quan trọng ghi nhận thành quả của quá trình nỗ lực học tập và nghiên cứu của các học viên, sinh viên dưới mái trường Học viện.</strong></em></p>\n\n<div class=\"wp-caption aligncenter\">\n    <img class=\"size-full\" src=\"/images/post_14/1.jpg\" alt=\"Toàn cảnh lễ tốt nghiệp\" />\n    <p class=\"wp-caption-text\">Toàn cảnh Lễ tốt nghiệp và trao bằng đợt 1 năm 2026 tại Học viện Công nghệ Bưu chính Viễn thông</p>\n</div>\n\n<p style=\"text-align: justify\">Tham dự buổi lễ có các đồng chí lãnh đạo Học viện, đại diện các Khoa đào tạo, các bậc phụ huynh và đặc biệt là sự hiện diện của gần 1.000 tân khoa. Trong không khí trang nghiêm và xúc động, các tân Tiến sỹ, Thạc sỹ và Kỹ sư đã cùng nhìn lại chặng đường đã qua với những kỷ niệm khó quên và niềm tự hào khi chính thức trở thành những chuyên gia công nghệ, nhà quản lý trong tương lai.</p>\n\n<div class=\"wp-caption aligncenter\">\n    <img class=\"size-full\" src=\"/images/post_14/2.jpg\" alt=\"Phát biểu chúc mừng\" />\n    <p class=\"wp-caption-text\">PGS. TS Đặng Hoài Bắc – Giám đốc Học viện phát biểu chúc mừng và giao nhiệm vụ cho các tân khoa</p>\n</div>\n\n<p style=\"text-align: justify\">Tại buổi lễ, đại diện Học viện đã công bố quyết định công nhận tốt nghiệp và thực hiện nghi thức trao bằng cho các tân Tiến sỹ, Thạc sỹ và Kỹ sư. Niềm vui rạng rỡ hiện rõ trên gương mặt của các bạn sinh viên khi nhận tấm bằng danh giá trên tay, đánh dấu sự khởi đầu cho một hành trình nghề nghiệp mới đầy triển vọng phía trước.</p>\n\n<div class=\"wp-caption aligncenter\">\n    <img class=\"size-full\" src=\"/images/post_14/3.jpg\" alt=\"Nghi thức trao bằng\" />\n    <p class=\"wp-caption-text\">Đại diện lãnh đạo Học viện trao bằng tốt nghiệp cho các tân khoa tiêu biểu</p>\n</div>\n\n<p style=\"text-align: justify\">Bên cạnh việc trao bằng, Học viện cũng đã tổ chức khen thưởng cho các sinh viên đạt thành tích xuất sắc trong học tập và rèn luyện toàn khóa học. Đây là sự ghi nhận xứng đáng cho những cố gắng không ngừng nghỉ của các em, đồng thời khích lệ tinh thần học tập suốt đời cho toàn thể sinh viên Học viện.</p>\n\n<div class=\"wp-caption aligncenter\">\n    <img class=\"size-full\" src=\"/images/post_14/4.jpg\" alt=\"Niềm vui ngày tốt nghiệp\" />\n    <p class=\"wp-caption-text\">Các tân khoa cùng rạng rỡ chụp ảnh lưu niệm ghi lại những khoảnh khắc đáng nhớ trong ngày tốt nghiệp</p>\n</div>\n\n<p style=\"text-align: justify\">Lễ tốt nghiệp đợt 1 năm 2026 khép lại thành công tốt đẹp, để lại nhiều ấn tượng sâu sắc. Chúc các tân Tiến sỹ, Thạc sỹ và Kỹ sư của Học viện sẽ tự tin vững bước trên con đường sự nghiệp, phát huy tốt những kiến thức đã học để đóng góp cho sự phát triển của xã hội và luôn tự hào là sinh viên của Học viện Công nghệ Bưu chính Viễn thông.</p>','/images/post_14/1.jpg','Sự kiện','10/04/2026',NULL),(15,'Học viện Công nghệ Bưu chính Viễn thông ra mắt Viện Lãnh đạo, Quản trị và Quản lý Việt Nam','hoc-vien-cong-nghe-buu-chinh-vien-thong-ra-mat-vien-lanh-dao-quan-tri-va-quan-ly-viet-nam','Sáng ngày 22/4, tại Hà Nội, Học viện Công nghệ Bưu chính Viễn thông đã chính thức ra mắt Viện Lãnh đạo, Quản trị và Quản lý Việt Nam (VML).','<p style=\"text-align: justify\"><em><strong>Sáng ngày 22/4, tại Hà Nội, Học viện Công nghệ Bưu chính Viễn thông đã chính thức ra mắt Viện Lãnh đạo, Quản trị và Quản lý Việt Nam (VML). Sự kiện đánh dấu một bước tiến mới của Học viện trong việc khẳng định vai trò đào tạo, bồi dưỡng và tư vấn về năng lực lãnh đạo, quản trị hiện đại cho cộng đồng doanh nghiệp và các tổ chức tại Việt Nam.</strong></em></p>\n\n<div class=\"wp-caption aligncenter\">\n    <img class=\"size-full\" src=\"/images/post_15/1.jpg\" alt=\"Lễ ra mắt Viện VML\" />\n    <p class=\"wp-caption-text\">Nghi thức chính thức ra mắt Viện Lãnh đạo, Quản trị và Quản lý Việt Nam (VML)</p>\n</div>\n\n<p style=\"text-align: justify\">Viện VML được thành lập với sứ mệnh trở thành trung tâm xuất sắc trong việc nghiên cứu, đào tạo và chuyển giao các kiến thức, kỹ năng quản trị tiên tiến. Viện tập trung vào các mảng hoạt động chính bao gồm: Đào tạo các kỹ năng lãnh đạo chiến lược; Tư vấn quản trị doanh nghiệp; và Tổ chức các diễn đàn, hội thảo về quản lý trong kỷ nguyên số. Với đội ngũ chuyên gia giàu kinh nghiệm thực chiến, VML kỳ vọng sẽ mang đến những giá trị thực chất, giúp các nhà quản lý bứt phá và thích ứng với môi trường kinh doanh đầy biến động.</p>\n\n<div class=\"wp-caption aligncenter\">\n    <img class=\"size-full\" src=\"/images/post_15/2.jpg\" alt=\"Trao quyết định bổ nhiệm\" />\n    <p class=\"wp-caption-text\">Lãnh đạo Học viện trao quyết định bổ nhiệm cho Hội đồng và Ban lãnh đạo Viện VML</p>\n</div>\n\n<p style=\"text-align: justify\">Tại buổi lễ, đại diện lãnh đạo Học viện đã giao nhiệm vụ cho Ban lãnh đạo Viện VML, nhấn mạnh việc xây dựng các chương trình đào tạo mang tính ứng dụng cao, gắn liền với nhu cầu thực tiễn của thị trường. Việc ra mắt Viện VML không chỉ mở rộng hệ sinh thái đào tạo của Học viện mà còn góp phần quan trọng vào việc nâng cao chất lượng nguồn nhân lực quản lý, đáp ứng yêu cầu chuyển đổi số và phát triển bền vững của đất nước.</p>\n\n<div class=\"wp-caption aligncenter\">\n    <img class=\"size-full\" src=\"/images/post_15/3.jpg\" alt=\"Chụp ảnh lưu niệm\" />\n    <p class=\"wp-caption-text\">Các đại biểu và khách mời chụp ảnh lưu niệm chúc mừng sự ra đời của Viện VML</p>\n</div>\n\n<p style=\"text-align: justify\">Sự kiện ra mắt đã thu hút đông đảo sự quan tâm của các doanh nghiệp, tổ chức và các chuyên gia trong lĩnh vực quản trị. Đây được coi là điểm khởi đầu đầy triển vọng cho một hành trình mới của Viện Lãnh đạo, Quản trị và Quản lý Việt Nam trong việc đồng hành cùng sự phát triển của các doanh nghiệp Việt.</p>','/images/post_15/1.jpg','Sự kiện','22/04/2026',NULL),(16,'PTIT khai trương Trung tâm Đào tạo và Phát triển Phần mềm Chất lượng cao (CESDT)','ptit-khai-truong-trung-tam-dao-tao-va-phat-trien-phan-mem-chat-luong-cao-cesdt','Ngày 27/11/2024, tại Thành phố Hồ Chí Minh, Học viện Công nghệ Bưu chính Viễn thông (PTIT) đã tổ chức Lễ khai trương Trung tâm Đào tạo và Phát triển Phần mềm Chất lượng cao (CESDT).','<p style=\"text-align: justify\"><strong>Ngày 27/11/2024, tại Thành phố Hồ Chí Minh, Học viện Công nghệ Bưu chính Viễn thông (PTIT) đã tổ chức Lễ khai trương Trung tâm Đào tạo và Phát triển Phần mềm Chất lượng cao (CESDT). Tham dự buổi lễ có: ông Sandeep Arya, Đại sứ Ấn Độ tại Việt Nam, Thứ trưởng Bộ Thông tin và Truyền thông (TT&TT) Phan Tâm, ông Vipra Pandey, Tổng Lãnh sự Ấn Độ tại Thành phố Hồ Chí Minh. Về phía Học viện có GS.TS Từ Minh Phương – Chủ tịch Hội đồng Học viện, PGS.TS Đặng Hoài Bắc – Giám đốc Học viện và đại diện lãnh đạo các đơn vị trực thuộc Bộ TT&TT, và các đơn vị đối tác của Học viện.</strong></p>\n\n<div id=\"attachment_33864\" class=\"wp-caption alignnone\">\n    <img class=\"wp-image-33864 size-full\" src=\"/images/post_16/1.jpg\" alt=\"Các đại biểu bấm nút khai trương\" />\n    <p id=\"caption-attachment-33864\" class=\"wp-caption-text\">Các đại biểu bấm nút khai trương Trung tâm Đào tạo và Phát triển Phần mềm Chất lượng cao (CESDT).</p>\n</div>\n\n<p style=\"text-align: justify\">TS. Tân Hạnh, Phó Giám đốc PTIT, phụ trách Trung tâm Đào tạo Bưu chính Viễn thông 2 (trực thuộc PTIT) cho biết, dự án hỗ trợ đào tạo về CNTT trong khuôn khổ hợp tác ASEAN – Ấn Độ, được Ấn Độ viện trợ không hoàn lại theo quỹ hợp tác ASEAN – Ấn Độ (AICF) với mục tiêu phát triển nguồn nhân lực CNTT chất lượng cao trong các quốc gia ASEAN, trong đó Việt Nam là một trong những quốc gia tham gia trọng điểm. Dự án này được thực hiện bởi Trung tâm Phát triển Công nghệ điện toán Tiên tiến (CDAC) thuộc Bộ Điện tử và Công nghệ Thông tin của Chính phủ Ấn Độ, là đơn vị tiên phong trong việc phát triển siêu máy tính và các giải pháp công nghệ thông tin tiên tiến có tầm ảnh hưởng toàn cầu, đồng thời chủ trì các dự án như CESDT để hỗ trợ phát triển ngành CNTT tại các quốc gia thuộc ASEAN.</p>\n\n<div id=\"attachment_33863\" class=\"wp-caption alignnone\">\n    <img class=\"wp-image-33863 size-full\" src=\"/images/post_16/2.jpg\" alt=\"TS. Tân Hạnh\" />\n    <p id=\"caption-attachment-33863\" class=\"wp-caption-text\">TS. Tân Hạnh, Phó Giám đốc phụ trách Học viện tại cơ sở thành phố Hồ Chí Minh</p>\n</div>\n\n<p style=\"text-align: justify\">Dự án tài trợ trị giá hơn 1,1 triệu đô la Mỹ bao gồm trang thiết bị, phần mềm, đào tạo Master Trainer tại Ấn Độ, phái cử chuyên gia Ấn Độ hỗ trợ vận hành tại Việt Nam, giấy phép ủy quyền, bản quyền các khóa học, … để hình thành một trung tâm đào tạo ủy quyền của CDAC tại Việt Nam.</p>\n<p style=\"text-align: justify\">Tại Việt Nam, Học viện Công nghệ Bưu chính Viễn thông là đơn vị duy nhất được thụ hưởng và thực hiện dự án này theo quyết định của Bộ trưởng Bộ Thông tin và Truyền thông. Học viện đã xây dựng đầu tư cơ sở vật chất tương xứng, tích hợp chương trình đào tạo của CDAC vào chương trình đào tạo dài hạn, đồng thời hợp tác với các doanh nghiệp CNTT để cung cấp các chương trình đào tạo ngắn hạn theo nhu cầu doanh nghiệp. Sinh viên, học viên tham gia chương trình đào tạo của dự án được học theo chương trình quốc tế, thực hành với dự án thực tế của doanh nghiệp và được cấp chứng chỉ quốc tế khi hoàn thành. Bên cạnh đó, sinh viên cũng được bổ sung các kỹ năng mềm, ngoại ngữ để có thể có được việc làm tốt nhất khi hoàn thành chương trình.</p>\n\n<div id=\"attachment_33865\" class=\"wp-caption alignnone\">\n    <img class=\"wp-image-33865 size-full\" src=\"/images/post_16/3.jpg\" alt=\"Ông Sandeep Arya\" />\n    <p id=\"caption-attachment-33865\" class=\"wp-caption-text\">Ông Sandeep Arya, Đại sứ Ấn Độ tại Việt Nam</p>\n</div>\n\n<p style=\"text-align: justify\">Ông Sandeep Arya, Đại sứ Ấn Độ tại Việt Nam chia sẻ, CESDT là một phần của quan hệ đối tác chiến lược toàn diện, đại diện cho sự tiếp nối các sáng kiến tương tự trong lĩnh vực CNTT, công nghệ số và dịch vụ phần mềm giữa Việt Nam và Ấn Độ. Trung tâm được kỳ vọng sẽ mang lại lợi ích to lớn cho các cán bộ và sinh viên Việt Nam cũng như các nước trong khu vực thông qua một loạt các khoá học trong các lĩnh vực như lập trình máy tính, truyền thông dữ liệu và mạng, công nghệ web, an ninh mạng, tự động hoá văn phòng…</p>\n<p style=\"text-align: justify\">Phát biểu tại buổi lễ Thứ trưởng Bộ TT&TT Phan Tâm cho biết, đối với Việt Nam, nguồn nhân lực số nhất là nguồn nhân lực chất lượng cao và đặc biệt là nhân tài trong bối cảnh chuyển đổi số sẽ là yếu tố đột phá cùng thể chế số và hạ tầng số để giúp Việt Nam thực hiện mục tiêu công nghiệp hóa, hiện đại hóa. Trong những năm qua, PTIT luôn là đơn vị tiên phong phát triển để đóng góp ngày càng nhiều hơn về số lượng, với chất lượng cao hơn cho nhân lực số Việt Nam.</p>\n\n<div id=\"attachment_33866\" class=\"wp-caption alignnone\">\n    <img class=\"wp-image-33866 size-full\" src=\"/images/post_16/4.jpg\" alt=\"Thứ trưởng Phan Tâm\" />\n    <p id=\"caption-attachment-33866\" class=\"wp-caption-text\">Thứ trưởng Bộ TT&TT Phan Tâm phát biểu tại buổi lễ ra mắt CESDT.</p>\n</div>\n\n<p style=\"text-align: justify\">Theo Thứ trưởng Bộ TT&TT Phan Tâm, việc khánh thành Trung tâm Đào tạo và Phát triển Phần mềm Chất lượng cao (CESDT) sẽ là một bước đi quan trọng trong chiến lược phát triển của PTIT. Bộ TT&TT tin tưởng rằng, với các chương trình đào tạo chuyên sâu về công nghệ thông tin, Trung tâm sẽ trở thành một nơi lý tưởng để đào tạo các chuyên gia công nghệ số đủ năng lực đáp ứng yêu cầu chuyển đổi số quốc gia.</p>\n<p style=\"text-align: justify\">Để tiếp tục phát huy hiệu quả dự án, tăng cường quan hệ hợp tác giữa hai nước, Bộ TT&TT đề nghị với Bộ Điện tử và Công nghệ Thông tin của Ấn Độ, Đại sứ Ấn Độ tại Việt Nam tiếp tục hỗ trợ các giảng viên của Học viện tham gia khóa đào tạo Master Trainer trong khuôn khổ dự án, mở rộng dự án trong giai đoạn tới để vừa phát huy giá trị của dự án và vừa gắn chặt quan hệ ngoại giao giữa hai nước Việt Nam và Ấn Độ.</p>\n<p style=\"text-align: justify\">Định hướng Trung tâm Đào tạo và Phát triển Phần mềm Chất lượng cao phát triển trong thời gian tới, thay mặt Bộ TT&TT, Thứ trưởng Phan Tâm yêu cầu Học viện, Trung tâm đào tạo tiếp tục mở rộng và tăng cường hợp tác với các tổ chức đào tạo quốc tế để khẳng định và đi đến công nhận kết quả các khóa đào tạo ngắn hạn của Trung tâm ở phạm vi trong nước, khu vực và quốc tế; Tăng cường kết nối theo mô hình 3 bên: Cơ sở đào tạo – Cơ sở nghiên cứu – Doanh nghiệp trên cơ sở bám sát nhu cầu thị trường và định hướng đào tạo của ngành, Quốc gia để đóng góp thực chất cho thị trường nhân lực số quốc gia.</p>\n<p style=\"text-align: justify\">Trung tâm đào tạo khẩn trương triển khai biên bản thoả thuận hợp với các đối tác bằng những hành động cụ thể để phát huy hiệu quả của dự án.</p>\n\n<table style=\"border-collapse: collapse;width: 100%\">\n<tbody>\n<tr>\n<td style=\"width: 100%;text-align: justify\"><span style=\"color: #0000ff\">Cũng tại sự kiện, Trung tâm Đào tạo Bưu chính Viễn thông 2 (đơn vị trực thuộc PTIT) được giao quản lý, vận hành CESDT đã ký thoả thuận hợp tác với các đối tác: Công ty cổ phần DevPlus để đào tạo kỹ năng và cung cấp nguồn nhân lực theo yêu cầu của các công ty phần mềm. Viện Thông tin và Quản lý Thuỵ Sỹ cùng Hệ thống văn bằng năng lực quốc gia Anh Quốc trong việc công nhận các chương trình đào tạo ngắn hạn cấp chứng chỉ của Trung tâm Đào tạo Bưu chính Viễn thông 2 và CESDT.</span></td>\n</tr>\n</tbody>\n</table>','/images/post_16/1.jpg','Sự kiện','27/11/2024',NULL),(17,'PTIT khánh thành cơ sở đào tạo mới trong ngày Hiến chương các nhà giáo Việt Nam','ptit-khanh-thanh-co-so-dao-tao-moi-trong-ngay-hien-chuong-cac-nha-giao-viet-nam','Ngày 20/11, tại Hà Nội, Học viện Công nghệ Bưu chính Viễn thông (PTIT) đã tổ chức lễ kỷ niệm 42 năm ngày Nhà giáo Việt Nam (20/11/1982 – 20/11/2024) và khánh thành khu nhà học tại sơ sở đào tạo Ngọc Trục.','<p style=\"text-align: justify\"><strong>Ngày 20/11, tại Hà Nội, Học viện Công nghệ Bưu chính Viễn thông (PTIT) đã tổ chức lễ kỷ niệm 42 năm ngày Nhà giáo Việt Nam (20/11/1982 – 20/11/2024) và khánh thành khu nhà học tại sơ sở đào tạo Ngọc Trục.</strong></p>\n<p style=\"text-align: justify\">Tham dự buổi Lễ, có Thứ trưởng Bộ Thông tin và Truyền thông Bùi Hoàng Phương, GS.TSKH Đỗ Trung Tá, nguyên Ủy viên Trung ương Đảng, nguyên Bộ trưởng Bộ Bưu chính Viễn thông, TS. Mai Liêm Trực, nguyên Tổng cục trưởng Tổng cục Bưu điện, Thứ trưởng Thường trực Bộ Bưu chính Viễn thông, ông Huỳnh Quang Liêm, Tổng Giám đốc Tập đoàn Bưu chính Viễn thông. Về phía Học viện có: GS.TS Từ Minh Phương – Bí thư Đảng ủy, Chủ tịch Hội đồng Học viện; PGS.TS Đặng Hoài Bắc – Giám đốc Học viện, các thế hệ lãnh đạo và gần 800 giảng viên và sinh viên đại diện cho toàn thể giảng viên, cán bộ công nhân viên và hơn 22.000 sinh viên toàn Học viện.</p>\n<p style=\"text-align: justify\">Tham dự buổi Lễ còn có các đối tác trong nước và quốc tế của Học viện; các cơ quan quản lý, chính quyền địa phương trên địa bàn mà học viện đặt trụ sở, cơ sở và các cơ quan thông tấn báo chí.</p>\n\n<div class=\"wp-caption alignnone\">\n    <img class=\"size-full\" src=\"/images/post_17/2.jpg\" alt=\"Thứ trưởng Bộ TT&TT tặng hoa\" />\n    <p class=\"wp-caption-text\">Thứ trưởng Bộ TT&TT Bùi Hoàng Phương tặng hoa chúc mừng 20/11 cho PTIT</p>\n</div>\n\n<p style=\"text-align: justify\">Phát biểu tại Lễ kỷ niệm, PGS. TS Đặng Hoài Bắc, Giám đốc Học viện đã gửi lời tri ân tới các thế hệ nhà giáo của Học viện, những người đã, đang và tiếp tục có những cống hiến quan trọng cho sự nghiệp trồng người và sự phát triển của Học viện, của đất nước, đưa nước ta vào kỷ nguyên số.</p>\n<p style=\"text-align: justify\">Giám đốc Học viện nhấn mạnh: Học viện là trường tiên phong về chuyển đổi số Giáo dục Đại học, là trường công nghệ hàng đầu cả nước, 1 trong 05 trường liên minh Đào tạo về Bán dẫn vi mạch. Học viện cũng tiên phong mở các ngành/chương trình đào tạo mới như Fintech, Công nghệ IoT, Kỹ thuật Dữ liệu, Thiết kế vi mạch, Báo chí số, Thiết kế Phát triển Game và là trường đầu tiên có khoa Trí tuệ nhân tạo. Học viện được Tổ chức Scimago quốc tế đánh giá Học viện là trường Đại học số 01 Việt Nam về Đổi mới sáng tạo năm 2024; Giải thưởng ASOCIO 2024 dành cho hạng mục EduTech (Công nghệ trong lĩnh vực giáo dục) do Hiệp hội Công nghiệp Điện toán Châu Á – Châu Đại Dương (ASOCIO) bình chọn. Năm học 2023-2024, Học viện đã khai trương các Văn phòng đại diện tại Hàn Quốc, Nhật Bản và có đại diện tại Úc, Đức Hoa kỳ, mở ra tiền đề để Học viện hội nhập sâu rộng, toàn cầu hóa, tiệm cận các chuẩn mực quốc tế trong giáo dục đại học. Năm 2024, cũng là năm “bùng nổ” giải thưởng quốc tế của sinh viên khi đã có nhiều sinh viên Học viện được tham gia và đạt giải nhất trong các cuộc thi quốc tế tại Úc, Mỹ, châu Âu, Hàn Quốc, Nhật  Bản. Một số dự án nghiên cứu của sinh viên Học viện mang tính công nghệ đột phá và thực tiễn cao được các Tập đoàn, Doanh nghiệp như Intel Huawei đánh giá xuất sắc như dự án “Aero ResQ: Hệ thống hỗ trợ tìm kiếm cứu nạn dựa trên sóng Wifi và ứng dụng AI trên UAV”… 100 sinh viên Học viện và sinh viên quốc tế đã được trao đổi thực tập tại Học viện và tại nước ngoài trong năm 2024, Học viện cũng đã tổ chức lớp đào tạo Thạc sỹ ngành Khoa học máy tính bằng Tiếng Anh cho sinh viên nước ngoài. “Đặc biệt, trong ngày vui hôm nay, Học viện vinh dự khi có 3 giảng viên được Hội đồng chức danh Giáo sư Nhà nước công nhận đạt chuẩn chức danh Giáo sư và Phó Giáo sư” Giám đốc Học viện chia sẻ.</p>\n\n<div class=\"wp-caption alignnone\">\n    <img class=\"size-full\" src=\"/images/post_17/3.jpg\" alt=\"Giám đốc Học viện phát biểu\" />\n    <p class=\"wp-caption-text\">PGS. TS Đặng Hoài Bắc, Giám đốc Học viện gửi lời tri ân tới các thế hệ nhà giáo của Học viện</p>\n</div>\n\n<p style=\"text-align: justify\">PGS. TS Đặng Hoài Bắc khẳng định: “Học viện đã có những thành quả nổi trội, kế thừa được nhiều di sản tiền nhân, cụ thể hóa được nhiều mong muốn của Lãnh đạo Bộ Thông tin và Truyền thông, nhưng những khó khăn vẫn còn ở trước mắt, sự cạnh tranh trong giáo dục đại học trong nước và quốc tế đang diễn ra mạnh mẽ, đòi hỏi những mục tiêu phát triển mới của Học viện phải cao hơn, tốc độ phát triển Học viện phải mạnh mẽ hơn nhưng vẫn phải chú trọng đến chất lượng, chiều sâu và sự bền vững. Học viện phải có lộ trình xây dựng được thế hệ nhân tài PTIT từ sinh viên, giảng viên trẻ của Học viện để kế thừa phát triển và bứt phá thực hiện những trọng trách này”.</p>\n<p style=\"text-align: justify\">Trong khuôn khổ Lễ kỷ niệm Ngày nhà Giáo Việt Nam 20/11, Học viện đã công bố và chúc mừng 3 nhà giáo được Hội đồng Giáo sư Nhà nước xét công nhận đạt tiêu chuẩn chức danh Giáo sư, Phó giáo sư năm 2024. Trong đó, Phó giáo sư Phạm Ngọc Anh, Trưởng khoa Cơ bản 1 được công nhận đạt chuẩn chức danh Giáo sư ngành Toán học, cùng 2 giảng viên đạt tiêu chuẩn chức danh Phó Giáo sư.</p>\n<p style=\"text-align: justify\">Tại buổi Lễ, Học viện đã tổ chức lễ khánh thành khu nhà học, ký túc xá cơ sở Học viện tại Ngọc Trục. Với tên ban đầu là Dự án “Xây dựng nhà hiệu bộ, lớp học, ký túc xá – Trung tâm đào tạo Bưu chính Viễn thông 1 – Học viện Công nghệ Bưu chính Viễn thông” do Tổng Công ty Bưu chính Viễn thông Việt Nam nay là Tập đoàn Bưu chính Viễn thông Việt Nam VNPT đầu tư, là dự án trọng điểm để nâng cao cơ sở vật chất của Học viện trong chiến lược phát triển đáp ứng nhiệm vụ đào tạo được Nhà nước giao phó. Dự án gồm: Nhà Hiệu bộ với 13 tầng, nhà ký túc xá 8 tầng và công trình phụ trợ; diện tích xây dựng 1.600m², diện tích sàn xây dựng 16.615m²; Công trình chính thức được khởi công xây dựng năm 2011. Đây là dự án phức tạp diễn ra trong thời gian dài, gặp nhiều khó khăn thách thức. Sau nhiều lần điều chỉnh, tạm ngừng thi công do dịch bệnh Covid-19, đến tháng 11 năm 2024, với sự nỗ lực không ngừng, sự vào cuộc của cả hệ thống chính trị, dự án chính thức hoàn thành và có thể đưa vào khai thác sử dụng. Kết quả này đánh dấu một cột mốc mới trong quá trình cải thiện và nâng cao điều kiện cơ sở vật chất, phục vụ công tác dạy và học của Học viện.</p>\n\n<div class=\"wp-caption alignnone\">\n    <img class=\"size-full\" src=\"/images/post_17/4.jpg\" alt=\"Cắt băng khánh thành\" />\n    <p class=\"wp-caption-text\">Nghi thức cắt băng khánh thành Cơ sở đào tạo Ngọc Trục.</p>\n</div>\n\n<p style=\"text-align: justify\">Phát biểu trong Lễ khai trương cơ sở mới, GS.TS Từ Minh Phương, Chủ tịch Hội đồng Học viện bày tỏ niềm vui mừng khi cơ sở đào tạo Ngọc Trục đã chính thức được khánh thành và đưa vào sử dụng. Đây là dấu mốc mới vô cùng ý nghĩa đáp ứng kỳ vọng của cán bộ, công nhân viên, giảng viên, sinh viên học viện, từng bước hoàn thiện về cơ sở vật chất, chất lượng phục vụ giảng dạy, nghiên cứu, nâng cao năng lực đào tạo và uy tín của Học viện.</p>\n<p style=\"text-align: justify\">Việc hoàn thành công trình chứng tỏ Học viện có đủ quyết tâm, năng lực thực hiện các dự án xây dựng, cơ bản quy mô, kể cả dự án có yếu tố phức tạp. Đây là cơ sở để Học viện tiếp tục tự tin học viện có nhiều dự án tăng cường cơ sở vật chất, tương xứng với vị thế quy mô và chiến lược phát triển của học viện.</p>\n\n<div class=\"wp-caption alignnone\">\n    <img class=\"size-full\" src=\"/images/post_17/5.jpg\" alt=\"Chủ tịch Hội đồng Học viện phát biểu\" />\n    <p class=\"wp-caption-text\">GS.TS Từ Minh Phương, Chủ tịch Hội đồng Học viện khẳng định: khánh thành khu nhà học cơ sở đào tạo Ngọc Trục là dấu mốc mới vô cùng ý nghĩa đáp ứng kỳ vọng của cán bộ, công nhân viên, giảng viên, sinh viên Học viện</p>\n</div>\n\n<p style=\"text-align: justify\">Công trình được hoàn thiện vào thời điểm không thể phù hợp hơn khi Học viện đang có nhu cầu cấp thiết về giảng đường lớp học, phòng làm việc giảng viên, phòng thí nghiệm hiện đại trong điều kiện cơ sở hiện có mặc dù đã được nâng cấp cải thiện đáng kể nhưng bắt đầu có dấu hiệu quá tải do sự phát triển rất nhanh, của học viện trong những năm gần đây. “Việc đưa vào sử dụng cơ sở đào tạo Ngọc Trục không chỉ góp phần mở rộng cảnh quan, khuôn viên của học viện nói chung, mà còn quảng bá hình ảnh, nâng tầm vị thế của học viện trước người học và xã hội. Sau buổi lễ khánh thành hôm nay, học viện sẽ khẩn trương triển khai phương án, đưa cơ sở đào tạo Ngọc Trục vào sử dụng, tận dụng tối đa và công năng của công trình”, Chủ tịch Hội đồng Học viện nhấn mạnh.</p>\n\n<div class=\"wp-caption alignnone\">\n    <img class=\"size-full\" src=\"/images/post_17/6.jpg\" alt=\"Thứ trưởng Bộ TT&TT phát biểu\" />\n    <p class=\"wp-caption-text\">Thứ trưởng Bộ Thông tin và Truyền thông Bùi Hoàng Phương phát biểu tại buổi Lễ</p>\n</div>\n\n<p style=\"text-align: justify\">Chung vui với thầy và trò Học viện Công nghệ Bưu chính Viễn thông, Thứ trưởng Bộ Thông tin và Truyền thông Bùi Hoàng Phương đã gửi những tình cảm tốt đẹp nhất đến các thế hệ nhà giáo, nhà khoa học, cán bộ, viên chức và đặc việt là 03 thầy giáo cô giáo được Hội đồng Giáo sư Nhà nước đạt chuẩn chức danh Giáo sư và Phó Giáo sư.</p>\n<p style=\"text-align: justify\">Học viện Công nghệ Bưu chính Viễn thông là đơn vị đào tạo đại học duy nhất của Bộ Thông tin và Truyền thông cần tiếp tục thực hiện sứ mệnh dẫn dắt chuyển đổi số giáo dục Việt Nam. Thứ trưởng mong muốn ban lãnh đạo cùng tất cả đội ngũ thầy cô giáo của học viện sẽ tiếp tục sự nghiệp trồng người với lòng nhiệt huyết, sự tận tâm, cống hiến để tiếp tục đào tạo cung cấp những thế hệ công dân toàn cầu, mang đậm dấu ấn Học viện.</p>\n<p style=\"text-align: justify\">“Tập thể lãnh đạo Bộ thông tin và Truyền thông ghi nhận những cố gắng của Ban lãnh đạo học viện trong quyết tâm triển khai và hoàn thành xây dựng cơ sở đào tạo Ngọc Trục trong đúng ngày đặc biệt này. Học viện cũng cần sớm triển khai đưa vào sử dụng ngay cơ sở đào tạo Ngọc Trục”, Thứ trưởng bày tỏ.</p>\n<p style=\"text-align: justify\">Cũng tại sự kiện, Lãnh đạo Bộ Thông tin và Truyền thông đã trao danh hiệu Chiến sỹ thi đua cấp Bộ giai đoạn 2021-2023 cho các cá nhân có thành tích đặc biệt xuất sắc, Bằng khen của Bộ trưởng cho 8 tập thể và 19 cá nhân có thành tích xuất sắc giai đoạn 2022-2023. Bên cạnh đó, 24 cán bộ, giảng viên, công nhân viên của Học viện  đã được trao Kỷ niệm chương “Vì sự nghiệp Thông tin và Truyền thông”, 9 cán bộ, giảng viên, công nhân viên của Học viện được trao Kỷ niệm chương  “Vì sự nghiệp Giáo dục và Đào tạo” của Bộ Giáo dục và Đào tạo. Học viện cũng đã trao giải cuộc thi Thiết kế Bài giảng điện tử trong cán bộ, giảng viên Học viện.</p>\n\n<p style=\"text-align: justify\">Một số hình ảnh tại chương trình:</p>\n<p style=\"text-align: center\"><img class=\"size-full\" src=\"/images/post_17/7.jpg\" alt=\"Hình ảnh chương trình 1\" /></p>\n<p style=\"text-align: center\"><img class=\"size-full\" src=\"/images/post_17/8.jpg\" alt=\"Hình ảnh chương trình 2\" /></p>\n<p style=\"text-align: center\"><img class=\"size-full\" src=\"/images/post_17/9.jpg\" alt=\"Hình ảnh chương trình 3\" /></p>\n<p style=\"text-align: center\"><img class=\"size-full\" src=\"/images/post_17/10.jpg\" alt=\"Hình ảnh chương trình 4\" /></p>','/images/post_17/1.jpg','Sự kiện','19/11/2024',NULL),(18,'PTIT tổ chức Hội nghị Khoa học sinh viên lần thứ 16','ptit-to-chuc-hoi-nghi-khoa-hoc-sinh-vien-lan-thu-16','Sáng ngày 22/5/2024, Học viện Công nghệ Bưu chính Viễn thông đã tổ chức Hội nghị Khoa học sinh viên lần thứ 16 nhằm thúc đẩy phong trào nghiên cứu khoa học và phát triển tư duy sáng tạo cho sinh viên.','<p style=\"text-align: justify\"><strong>Nhằm thúc đẩy phong trào nghiên cứu khoa học trong sinh viên, sáng ngày 22/5/2024, Học viện Công nghệ Bưu chính Viễn thông đã tổ chức Hội nghị Khoa học sinh viên lần thứ 16. Tham dự Hội nghị có PGS.TS Trần Quang Anh, Phó Giám đốc Học viện; đại diện lãnh đạo các Khoa đào tạo, các phòng ban chức năng cùng đông đảo các bạn sinh viên có niềm đam mê nghiên cứu khoa học của Học viện.</strong></p>\n\n<div class=\"wp-caption alignnone\">\n    <img class=\"size-full\" src=\"/images/post_18/2.jpg\" alt=\"Toàn cảnh hội nghị\" />\n    <p class=\"wp-caption-text\">Toàn cảnh Hội nghị Khoa học sinh viên lần thứ 16 tại Học viện</p>\n</div>\n\n<p style=\"text-align: justify\">Phát biểu khai mạc Hội nghị, PGS.TS Trần Quang Anh, Phó Giám đốc Học viện nhấn mạnh: “Nghiên cứu khoa học là một trong những hoạt động trọng tâm của Học viện, góp phần nâng cao chất lượng đào tạo và phát triển tư duy sáng tạo cho sinh viên. Hội nghị Khoa học sinh viên lần thứ 16 là sân chơi bổ ích để các em trình bày các kết quả nghiên cứu, trao đổi học thuật và rèn luyện kỹ năng thực tiễn.”</p>\n\n<div class=\"wp-caption alignnone\">\n    <img class=\"size-full\" src=\"/images/post_18/3.jpg\" alt=\"Lãnh đạo phát biểu\" />\n    <p class=\"wp-caption-text\">PGS.TS Trần Quang Anh, Phó Giám đốc Học viện phát biểu khai mạc Hội nghị</p>\n</div>\n\n<p style=\"text-align: justify\">Hội nghị năm nay thu hút gần 200 đề tài nghiên cứu đến từ sinh viên các Khoa trong toàn Học viện, tập trung vào các lĩnh vực công nghệ mũi nhọn như: Trí tuệ nhân tạo (AI), Internet vạn vật (IoT), An toàn thông tin, Truyền thông đa phương tiện, và Kinh tế số. Nhiều đề tài được Hội đồng đánh giá cao về tính mới, tính ứng dụng và khả năng phát triển thành các sản phẩm thực tế.</p>\n\n<div class=\"wp-caption alignnone\">\n    <img class=\"size-full\" src=\"/images/post_18/4.jpg\" alt=\"Sinh viên trình bày đề tài\" />\n    <p class=\"wp-caption-text\">Các nhóm sinh viên tự tin trình bày kết quả nghiên cứu trước Hội đồng chuyên môn</p>\n</div>\n\n<p style=\"text-align: justify\">Sau các phiên trình bày tại các tiểu ban chuyên môn, Ban tổ chức đã trao giải cho các đề tài xuất sắc nhất, bao gồm giải Nhất, Nhì, Ba và Khuyến khích. Thành công của Hội nghị tiếp tục khẳng định vị thế của Học viện trong việc chú trọng đào tạo nguồn nhân lực chất lượng cao, có khả năng thích ứng và dẫn dắt trong kỷ nguyên số.</p>\n\n<div class=\"wp-caption alignnone\">\n    <img class=\"size-full\" src=\"/images/post_18/5.jpg\" alt=\"Trao giải cho sinh viên\" />\n    <p class=\"wp-caption-text\">Đại diện Ban tổ chức trao giải cho các nhóm sinh viên đạt thành tích xuất sắc tại Hội nghị</p>\n</div>','/images/post_18/1.jpg','Sự kiện','22/05/2024',NULL),(19,'PTIT đạt giải thưởng ASOCIO 2024 về chuyển đổi số giáo dục đại học','ptit-dat-giai-thuong-asocio-2024-ve-chuyen-doi-so-giao-duc-dai-hoc','Ngày 07/11/2024, tại Tokyo, Nhật Bản, trong khuôn khổ Hội nghị Thượng đỉnh Công nghệ ASOCIO 2024, Học viện Công nghệ Bưu chính Viễn thông (PTIT) đã vinh dự nhận giải thưởng ASOCIO 2024 cho hạng mục Edutech.','<p style=\"text-align: justify\"><strong>Ngày 07/11/2024, tại Tokyo, Nhật Bản, trong khuôn khổ Hội nghị Thượng đỉnh Công nghệ ASOCIO (ASOCIO Digital Summit) 2024, Học viện Công nghệ Bưu chính Viễn thông (PTIT) đã vinh dự nhận giải thưởng ASOCIO 2024 cho hạng mục Edutech (Công nghệ trong lĩnh vực giáo dục). Giải thưởng này ghi nhận những nỗ lực và kết quả đột phá của Học viện trong chiến lược chuyển đổi số giáo dục đại học, khẳng định vị thế và uy tín của Học viện trên bản đồ công nghệ khu vực và thế giới.</strong></p>\n\n<div class=\"wp-caption alignnone\">\n    <img class=\"size-full\" src=\"/images/post_19/2.jpg\" alt=\"Đại diện Học viện nhận giải thưởng\" />\n    <p class=\"wp-caption-text\">Đại diện Học viện Công nghệ Bưu chính Viễn thông nhận giải thưởng ASOCIO 2024 tại Tokyo, Nhật Bản</p>\n</div>\n\n<p style=\"text-align: justify\">ASOCIO (Hiệp hội Công nghiệp Điện toán Châu Á – Châu Đại Dương) là tổ chức thương mại quốc tế uy tín bậc nhất trong lĩnh vực CNTT tại khu vực, đại diện cho hơn 10.000 doanh nghiệp từ 24 quốc gia và nền kinh tế thành viên. Giải thưởng ASOCIO được trao hàng năm nhằm vinh danh các cá nhân, cơ quan và doanh nghiệp có đóng góp xuất sắc cho sự phát triển của ngành CNTT và thúc đẩy chuyển đổi số.</p>\n\n<p style=\"text-align: justify\">Vượt qua nhiều vòng thẩm định và đánh giá khắt khe của Hội đồng chuyên môn quốc tế, Học viện đã xuất sắc giành giải thưởng tại hạng mục Edutech. Đây là sự ghi nhận xứng đáng cho hệ sinh thái giáo dục số toàn diện mà Học viện đã xây dựng, bao gồm: hệ thống quản lý đào tạo trực tuyến (LMS), học liệu số phong phú, hạ tầng phòng thí nghiệm ảo và các ứng dụng AI hỗ trợ cá nhân hóa lộ trình học tập cho sinh viên.</p>\n\n<div class=\"wp-caption alignnone\">\n    <img class=\"size-full\" src=\"/images/post_19/3.jpg\" alt=\"Đại biểu chúc mừng\" />\n    <p class=\"wp-caption-text\">Lãnh đạo ASOCIO và các đại biểu chúc mừng thành công của Học viện</p>\n</div>\n\n<p style=\"text-align: justify\">Phát biểu tại buổi lễ, đại diện Học viện nhấn mạnh: “Giải thưởng ASOCIO 2024 không chỉ là niềm tự hào của riêng PTIT mà còn là minh chứng cho sự phát triển mạnh mẽ của giáo dục đại học Việt Nam trong kỷ nguyên số. Chúng tôi cam kết tiếp tục đổi mới sáng tạo, ứng dụng những công nghệ tiên tiến nhất để mang lại trải nghiệm học tập tốt nhất cho sinh viên và cung cấp nguồn nhân lực chất lượng cao cho thị trường toàn cầu.”</p>\n\n<p style=\"text-align: justify\">Thành công này tiếp tục khẳng định hướng đi đúng đắn của Học viện trong việc thực hiện sứ mệnh dẫn dắt chuyển đổi số giáo dục quốc gia, đồng thời mở ra nhiều cơ hội hợp tác quốc tế trong nghiên cứu và đào tạo công nghệ cao trong tương lai.</p>','/images/post_19/1.jpg','Sự kiện','07/11/2024',NULL),(20,'Hơn 900 tân Tiến sỹ, tân Thạc sỹ và tân Cử nhân, tân Kỹ sư Học viện Công nghệ Bưu chính Viễn thông được trao bằng trong Lễ tốt nghiệp năm 2024 đợt 2','hon-900-tan-tien-sy-tan-thac-sy-va-tan-cu-nhan-tan-ky-su-hoc-vien-cong-nghe-buu-chinh-vien-thong-duoc-trao-bang-trong-le-tot-nghiep-nam-2024-dot-2','Ngày 25/10/2024, Học viện Công nghệ Bưu chính Viễn thông đã tổ chức Lễ tốt nghiệp năm 2024-đợt 2, cho 05 Tiến sĩ, hơn 40 Thạc sĩ và hơn 900, Cử nhân, Kỹ sư.','<p style=\"text-align: justify\"><strong>Ngày 25/10/2024, Học viện Công nghệ Bưu chính Viễn thông đã tổ chức Lễ tốt nghiệp năm 2024-đợt 2, cho 05 Tiến sĩ, hơn 40 Thạc sĩ và hơn 900, Cử nhân, Kỹ sư. Tham dự buổi Lễ có, PGS.TS Đặng Hoài Bắc, Giám đốc Học viện, TS. Nguyễn Trung Kiên, Phó Giám đốc Học viện cùng đại diện Lãnh đạo các đơn vị, khoa, phòng, ban chức năng Học viện.</strong></p>\n\n<p style=\"text-align: justify\">Theo thông tin tại phát biểu của Phó Giám đốc Học viện tại buổi lễ, hiện nay Học viện đã có 05 chương trình đào tạo trình độ tiến sĩ, 05 chuyên ngành trình độ thạc sĩ và 22 chương trình/ngành đào tạo trình độ Đại học với lưu lượng khoảng 20 ngàn học viên, sinh viên. Cùng với những ngành đào tạo chủ lực về Công nghệ thông tin, Viễn thông, Điện Điện tử, Học viện đã mở những ngành, chương trình đào tạo mới phục vụ Cách mạng công nghiệp 4.0 và Chuyển đổi số như Kỹ thuật dữ liệu, Công nghệ IoT, Robot AI Thiết kế IC; Học viện cũng là 1 trong 5 trường đại học hàng đầu khối kinh tế với những ngành nghề lai ghép công nghệ số như Công nghệ tài chính, thương mại điện tử, Maketing số; Truyền thông Đa phương tiện, Báo chí số… Năm 2024, Học viện mở thêm một số chương trình đào tạo mới, đáp ứng xu hướng nguồn nhân lực như: Quan hệ công chúng, Công nghệ thông tin Việt Nhật; Thiết kế và phát triển Game…</p>\n\n<div class=\"wp-caption alignnone\">\n    <img class=\"size-full\" src=\"/images/post_20/1.jpg\" alt=\"TS. Nguyễn Trung Kiên phát biểu\" />\n    <p class=\"wp-caption-text\">TS. Nguyễn Trung Kiên, Phó Giám đốc Học viện phát biểu tại buổi Lễ</p>\n</div>\n\n<p style=\"text-align: justify\"><strong>Đối với hoạt động đào tạo sau đại học</strong>, năm học 2024 – 2025, Học viện đã tổ chức bảo vệ thành công luận án tiến sĩ cấp cơ sở cho 6 NCS và cấp Học viện cho 18 NCS và có khoảng hơn 350 học viên cao học. Các luận án tiến sĩ nghiên cứu tại Học viện được đánh giá là các công trình nghiên cứu chuyên sâu, có tính thời sự, mang tính cấp thiết; sử dụng phương pháp, công cụ nghiên cứu hiện đại, phù hợp với điều kiện nghiên cứu của Việt Nam. Nội dung nghiên cứu trong đa số luận án được đánh giá có tính học thuật cao, thể hiện được tính kế thừa, áp dụng và phát triển có sáng tạo những thành tựu khoa học công nghệ tiên tiến trên thế giới. Đóng góp, đề xuất mới có giá trị khoa học và thực tiễn của các đề tài luận án đều được công bố, đăng tải trên các tạp chí chuyên ngành có uy tín, trong tuyển tập các báo cáo ở các Hội nghị khoa học trong và ngoài nước. Các đề án của học viên cao học thì có tính ứng dụng và hiệu quả trên cơ sở gắn kết Đào tạo – Nghiên cứu khoa học – Sản xuất kinh</p>\n\n<div class=\"wp-caption alignnone\">\n    <img class=\"size-full\" src=\"/images/post_20/2.jpg\" alt=\"Trao bằng Tiến sĩ\" />\n    <p class=\"wp-caption-text\">PGS.TS Đặng Hoài Bắc, Giám đốc Học viện và PGS.TS Lê Nhật Thăng, Trưởng khoa Đào tạo Sau Đại học trao bằng cho các Tân Tiến sĩ</p>\n</div>\n\n<div class=\"wp-caption alignnone\">\n    <img class=\"size-full\" src=\"/images/post_20/3.jpg\" alt=\"Các tân Thạc sĩ\" />\n    <p class=\"wp-caption-text\">Các tân Thạc sĩ nhận bằng tại buổi Lễ</p>\n</div>\n\n<p style=\"text-align: justify\"><strong>Đối với hoạt động đào tạo đại học,</strong> khóa D20 khối các ngành Kinh tế (Quản trị kinh doanh, Tài chính Kế toán, Marketing, Thương mại Điện tử) có 135 sinh viên tốt nghiệp xuất sắc và giỏi chiếm 23%, 437 sinh viên tốt nghiệp khá chiếm 74% và chỉ có 3 3,05% sinh viên tốt nghiệp trung bình. Cùng với hoạt động học tập, nghiên cứu khoa học, sinh viên khóa D20 khối ngành kinh tế còn tích cực tham gia các cuộc thi cấp quốc gia với nhiều thành tích vượt trội. Năm 2023, đội thi gồm 5 sinh viên ngành Thương mại điện tử đã giành giải Nhất cuộc thi toàn quốc “Sinh viên tài năng kinh doanh số”. 02 đội thi gồm 10 sinh viên ngành Thương mại Điện tử đã xuất sắc giành 01 giải Nhất và giải Nhì tại cuộc thi Toàn quốc “Genesis 2023- Ý tưởng khởi nghiệp sáng tạo dành cho sinh viên nữ”.</p>\n\n<div class=\"wp-caption alignnone\">\n    <img class=\"size-full\" src=\"/images/post_20/4.jpg\" alt=\"Các tân Cử nhân\" />\n    <p class=\"wp-caption-text\">Các tân Cử nhân, tân Kĩ sư nhận bằng tại buổi Lễ</p>\n</div>\n\n<p style=\"text-align: justify\">Phát biểu chúc mừng tại buổi Lễ, TS. Nguyễn Trung Kiên, Phó Giám đốc Học viện đánh giá cao kết quả học tập, nghiên cứu mà các tân Tiến sĩ, tân Thạc sĩ, tân Cử nhân, tân Kĩ sư đã đạt được trong suốt quá trình học tập. Phó Giám đốc Học viện nhắn nhủ: “Hành trình vạn dặm bắt đầu từ những bước chân đầu tiên, hành trình con đường sự nghiệp của các em sẽ bắt đầu từ ngày hôm nay, ngay khi các em cầm trên tay tấm bằng đại học danh giá của Học viện. Một hành trình mới bắt đầu với muôn vàn khó khăn và thử thách sẽ chờ đợi các em. Các em hãy chọn việc mình thích, làm việc mình giỏi và một công việc có thể tạo ra nhiều giá trị cho xã hội chính là mong mỏi của chúng tôi”.</p>\n\n<div class=\"wp-caption alignnone\">\n    <img class=\"size-full\" src=\"/images/post_20/5.jpg\" alt=\"Tân Tiến sĩ phát biểu\" />\n    <p class=\"wp-caption-text\">Tân Tiến sĩ Lê Thị Thùy Dương, ngành Kỹ thuật Viễn thông phát biểu tri ân thầy cô tại buổi Lễ</p>\n</div>\n\n<p style=\"text-align: justify\">Tân Tiến sĩ Lê Thị Thùy Dương, ngành Kỹ thuật Viễn thông đã đại diện cho các tân Tiến sĩ, tân Thạc sĩ, tân Cử nhân, tân Kĩ sư bày tỏ lòng tri ân đối với các giảng viên Học viện đã tận tình dạy bảo, giúp đỡ các nghiên cứu sinh, học viên và sinh viên trong suốt quá trình học tập và nghiên cứu tại Học viện. Tân Tiến sĩ khẳng định, những tri thức được lĩnh hội trong suốt quá trình học tập, nghiên cứu tại Học viện sẽ là cơ sở, là nền tảng để các Tân Tiến sĩ, Thạc sĩ, Cử nhân, Kỹ sư cống hiến, góp phần xây dựng quê hương, đất nước.</p>\n\n<div class=\"wp-caption alignnone\">\n    <img class=\"size-full\" src=\"/images/post_20/6.jpg\" alt=\"Thủ khoa phát biểu\" />\n    <p class=\"wp-caption-text\">Thủ khoa ngành Marketing Nguyễn Thị Nhung đại diện các tân Cử nhân, tân Kĩ sư gửi lời tri ân sâu sắc đến tập thể Lãnh đạo, các thầy cô và cán bộ Học viện</p>\n</div>\n\n<p style=\"text-align: justify\">Tân Cử nhân Nguyễn Thị Nhung, Thủ khoa ngành Marketing cũng đã đại diện các tân Cử nhân, tân Kĩ sư gửi lời tri ân sâu sắc đến tập thể Lãnh đạo, các thầy cô và cán bộ Học viện đã dìu dắt các em trong suốt những năm tháng qua, và hứa sẽ tiếp tục nỗ lực học tập, nghiên cứu để vững bước trên chặng đường tương lai, trở thành những công dân có ích cho xã hội để không phụ lòng mong đợi của quý thầy cô, gia đình”.</p>\n\n<div class=\"wp-caption alignnone\">\n    <img class=\"size-full\" src=\"/images/post_20/7.jpg\" alt=\"Trao thưởng thủ khoa\" />\n    <p class=\"wp-caption-text\">PGS.TS Đặng Hoài Bắc, Giám đốc Học viện và TS. Nguyễn Trung Kiên, Phó Giám đốc Học viện trao bằng, giấy khen, kỷ niệm chương cho các tân Cử nhân là thủ khoa tốt nghiệp của các ngành đào tạo khoá D20 các ngành khối kinh tế</p>\n</div>\n\n<p style=\"text-align: justify\">Tại buổi Lễ, Học viện đã trao bằng, Giấy khen, kỷ niệm chương cho các tân Cử nhân là thủ khoa tốt nghiệp của các ngành đào tạo khóa D20, các cử nhân tốt nghiệp loại xuất sắc, giỏi và các tân cử nhân tiêu biểu có thành tích cao trong học tập, rèn luyện, nghiên cứu khoa học và công tác đoàn khóa D20 các ngành khối kinh tế.</p>\n\n<div class=\"wp-caption alignnone\">\n    <img class=\"size-full\" src=\"/images/post_20/8.jpg\" alt=\"Trao học bổng\" />\n    <p class=\"wp-caption-text\">Đại diện Lãnh đạo Tập đoàn Công nghiệp Viễn thông quân đội Viettel trao biểu trung chương trình học bổng cho học viên cao học đang học tập, nghiên cứu tại Học viện</p>\n</div>\n\n<p style=\"text-align: justify\">Cũng trong khuôn khổ chương trình, đại diện Lãnh đạo Tập đoàn Công nghiệp Viễn thông quân đội Viettel đã trao chương trình học bổng giáo dục cho các học viên cao học đang học tập, nghiên cứu tại Học viện.</p>','/images/post_20/2.jpg','Sự kiện','25/10/2024',NULL),(21,'Học bổng Panasonic 2026 chính thức mở đơn: Nâng bước nhân tài – Vươn tới tương lai','hoc-bong-panasonic-2026-chinh-thuc-mo-don-nang-buoc-nhan-tai-vuon-toi-tuong-lai','Chương trình Học bổng Panasonic 2026 chính thức được triển khai nhằm tìm kiếm và hỗ trợ những sinh viên xuất sắc, có tinh thần vượt khó, đóng góp vào sự phát triển bền vững của xã hội.','<p style=\"text-align: justify\"><em><strong>Chương trình Học bổng Panasonic 2026 đã chính thức được triển khai, tiếp tục khẳng định cam kết của Panasonic trong việc đồng hành cùng sự nghiệp giáo dục và phát triển nguồn nhân lực tại Việt Nam. Với thông điệp “Nâng bước nhân tài – Vươn tới tương lai”, học bổng năm nay hướng tới việc tìm kiếm và hỗ trợ những sinh viên có thành tích học tập xuất sắc, có tinh thần vượt khó và khao khát đóng góp cho cộng đồng.</strong></em></p>\n\n<div class=\"wp-caption aligncenter\">\n    <img class=\"size-full\" src=\"/images/post_21/1.jpg\" alt=\"Học bổng Panasonic 2026\" />\n    <p class=\"wp-caption-text\">Chương trình Học bổng Panasonic 2026 chính thức nhận hồ sơ đăng ký</p>\n</div>\n\n<p style=\"text-align: justify\">Panasonic Scholarship là một trong những chương trình học bổng uy tín và lâu đời nhất dành cho sinh viên Việt Nam. Kể từ khi bắt đầu triển khai, chương trình đã trao cơ hội cho hàng trăm sinh viên ưu tú, giúp các bạn không chỉ giảm bớt gánh nặng tài chính mà còn được tham gia các chương trình đào tạo kỹ năng mềm, tham quan nhà máy và giao lưu cùng các chuyên gia hàng đầu của Panasonic.</p>\n\n<h3 style=\"text-align: justify\">Giá trị học bổng và quyền lợi:</h3>\n<ul style=\"text-align: justify\">\n    <li>Mức hỗ trợ tài chính lên đến 30.000.000 VNĐ/năm học.</li>\n    <li>Cơ hội tham gia các khóa đào tạo kỹ năng chuyên nghiệp từ tập đoàn Panasonic.</li>\n    <li>Ưu tiên tuyển dụng vào làm việc tại các công ty thuộc tập đoàn Panasonic tại Việt Nam sau khi tốt nghiệp.</li>\n</ul>\n\n<h3 style=\"text-align: justify\">Điều kiện và quy trình xét tuyển:</h3>\n<p style=\"text-align: justify\">Học bổng dành cho các sinh viên đang theo học hệ đại học chính quy tại các trường đại học trên toàn quốc, đặc biệt ưu tiên các khối ngành Kỹ thuật, Công nghệ, Kinh tế và Quản trị kinh doanh. Các ứng viên sẽ trải qua các vòng xét duyệt hồ sơ và phỏng vấn trực tiếp với hội đồng tuyển chọn của Panasonic Việt Nam.</p>\n\n<p style=\"text-align: justify\">Đây là cơ hội quý giá để sinh viên PTIT nói riêng và sinh viên cả nước nói chung bứt phá giới hạn và chuẩn bị hành trang tốt nhất cho sự nghiệp tương lai.</p>','/images/post_21/1.jpg','Học bổng','08/04/2026','ptit'),(22,'Thông báo chương trình học bổng Activator Scholarship của BGSW Vietnam','thong-bao-chuong-trinh-hoc-bong-activator-scholarship-cua-bgsw-vietnam','Học viện Công nghệ Bưu chính Viễn thông (PTIT) phối hợp cùng Công ty TNHH Bosch Global Software Technologies (BGSW) Việt Nam triển khai chương trình học bổng \"Activator Scholarship\" dành cho sinh viên năm cuối.','<p style=\"text-align: justify\"><em><strong>Học viện Công nghệ Bưu chính Viễn thông (PTIT) phối hợp cùng Công ty TNHH Bosch Global Software Technologies (BGSW) Việt Nam chính thức triển khai chương trình học bổng \"Activator Scholarship\". Đây là sáng kiến nhằm tìm kiếm, bồi dưỡng và hỗ trợ những tài năng công nghệ trẻ, chuẩn bị nguồn nhân lực chất lượng cao cho ngành công nghiệp phần mềm và giải trí số.</strong></em></p>\n\n<div class=\"wp-caption aligncenter\">\n    <img class=\"size-full\" src=\"/images/post_22/1.jpg\" alt=\"Học bổng Activator Scholarship\" />\n    <p class=\"wp-caption-text\">Chương trình học bổng Activator Scholarship dành cho sinh viên xuất sắc PTIT</p>\n</div>\n\n<p style=\"text-align: justify\">Chương trình không chỉ mang lại hỗ trợ về mặt tài chính mà còn mở ra cánh cửa thực tập và làm việc tại một trong những trung tâm phần mềm hàng đầu khu vực của Bosch. Các bạn sinh viên nhận học bổng sẽ được tham gia vào các dự án thực tế, làm việc cùng các chuyên gia quốc tế và tiếp cận quy trình phát triển sản phẩm chuyên nghiệp.</p>\n\n<h3 style=\"text-align: justify\">Thông tin chi tiết về học bổng:</h3>\n<ul style=\"text-align: justify\">\n    <li><strong>Đối tượng:</strong> Sinh viên năm cuối thuộc các khối ngành CNTT, An toàn thông tin, Điện tử Viễn thông và các ngành kỹ thuật liên quan.</li>\n    <li><strong>Giá trị học bổng:</strong> 10.000.000 VNĐ/suất tiền mặt cùng các gói đào tạo chuyên sâu về kỹ năng mềm và kỹ thuật.</li>\n    <li><strong>Quyền lợi bổ sung:</strong> Ưu tiên xét tuyển vào chương trình Thực tập sinh và nhân viên chính thức tại BGSW Việt Nam.</li>\n</ul>\n\n<p style=\"text-align: justify\">Để tham gia ứng tuyển, sinh viên cần có điểm trung bình tích lũy (GPA) đạt loại Khá trở lên và có khả năng giao tiếp bằng tiếng Anh tốt. Hội đồng tuyển chọn sẽ đánh giá dựa trên hồ sơ năng lực và các vòng phỏng vấn kỹ thuật trực tiếp.</p>\n\n<p style=\"text-align: justify\">Đây là cơ hội tuyệt vời để các bạn sinh viên khẳng định năng lực bản thân và rút ngắn khoảng cách từ giảng đường đến môi trường làm việc chuyên nghiệp toàn cầu.</p>','/images/post_22/1.jpg','Học bổng','04/04/2026','ptit'),(23,'Thông báo chương trình Học bổng tìm kiếm tài năng nghiên cứu “Viettel Research Excellence Scholarship”','thong-bao-chuong-trinh-hoc-bong-tim-kiem-tai-nang-nghien-cuu-viettel-research-excellence-scholarship','Căn cứ thỏa thuân hợp tác giữa Học viện Công nghệ Bưu chính Viễn thông và Tập đoàn Công nghệp – Viễn thông Quân đội (Viettel). Thực hiện trách nhiệm của Viettel trong việc phát triển nguồn nhân lực chất lượng cao cho đất nước...','<p style=\"text-align: justify\">Căn cứ thỏa thuân hợp tác giữa Học viện Công nghệ Bưu chính Viễn thông và Tập đoàn Công nghệp – Viễn thông Quân đội (Viettel). Thực hiện trách nhiệm của Viettel trong việc phát triển nguồn nhân lực chất lượng cao cho đất nước, đặc biệt là nhân sự lĩnh vực công nghệ số. Tập đoàn Viettel triền khai chương trình học bổng tìm kiếm tài năng nghiên cứu “Viettel Research Excellence Scholarship” năm 2024 tại Học viện Công nghệ Bưu chính Viễn thông (PTIT). Cụ thể như sau:</p>\n<p style=\"text-align: justify\"><strong>1. Mục tiêu:</strong> Thông qua hoạt động tài trợ giáo dục, Viettel mong muốn hỗ trợ tài chính để sinh viên, học viên tài năng có điều kiện học tập, nghiên cứu tốt, giúp hoàn thiện năng lực bản thân và có thể ứng dụng công nghệ tham gia giải quyết các vấn đề thực tiễn cho xã hội.</p>\n<p style=\"text-align: justify\"><strong>2. Nội dung chương trình:</strong></p>\n<p style=\"text-align: justify\"><strong>– Đối tượng:</strong> Học bổng dành cho sinh viên theo học thạc sĩ định hướng nghiên cứu các chuyên ngành công nghệ cao (Kỹ thuật điện tử, Kỹ thuật Viễn thông, Kỹ thuật điều khiển tự động hóa, Công nghệ thông tin…). Học viên có kết quả tốt trong quá trình học Đại học; Ưu tiên ứng viên có thành tích đặc biệt trong nghiên cứu khoa học, các kỳ thi chuyên môn nghiệp vụ, thi Olympic các môn khoa học các cấp; đồng thời đăng ký thực hiện các đề tài nghiên cứu khoa học công nghệ mới, sáng tạo, có khả năng ứng dụng cao.</p>\n<p style=\"text-align: justify\"><strong>– Số lượng dự kiến:</strong> 05 suất học bổng.</p>\n<p style=\"text-align: justify\"><strong>– Giá trị học bổng:</strong> 50.000.000 đồng/suất/ năm.</p>\n<p style=\"text-align: justify\"><strong>– Tổng giá trị tài trợ dự kiến:</strong> 50.000.000đồng*5 suất = 250.000.000đồng.</p>\n<p style=\"text-align: justify\"><em>Học viện Công nghệ Bưu chính Viễn thông trân trọng thông báo!</em></p>','/images/post_23/1.jpg','Học bổng','03/10/2024','ptit'),(24,'Học viện Công nghệ Bưu chính Viễn thông thêm đối tượng được hưởng học bổng 100% học phí','hoc-vien-cong-nghe-buu-chinh-vien-thong-them-doi-tuong-duoc-huong-hoc-bong-100-hoc-phi','Nhằm khuyến khích các tài năng trẻ, Học viện Công nghệ Bưu chính Viễn thông (PTIT) vừa quyết định mở rộng đối tượng được nhận học bổng toàn phần 100% học phí cho các thí sinh đạt giải cao trong kỳ thi học sinh giỏi quốc gia.','<p style=\"text-align: justify\"><em><strong>Chiều ngày 28/3, Học viện Công nghệ Bưu chính Viễn thông (PTIT) đã chính thức công bố việc điều chỉnh và bổ sung đối tượng được hưởng chính sách học bổng đặc biệt. Theo đó, Học viện sẽ mở rộng cơ hội nhận học bổng miễn 100% học phí trong suốt quá trình học tập cho nhiều thí sinh tài năng hơn nữa.</strong></em></p>\n\n<div class=\"wp-caption aligncenter\">\n    <img class=\"size-full\" src=\"/images/post_24/1.jpg\" alt=\"Chính sách học bổng PTIT\" />\n    <p class=\"wp-caption-text\">Học viện Công nghệ Bưu chính Viễn thông tiếp tục ưu tiên thu hút nhân tài bằng các gói học bổng hấp dẫn</p>\n</div>\n\n<p style=\"text-align: justify\">Cụ thể, bên cạnh những đối tượng đã được quy định trong đề án tuyển sinh, Học viện quyết định bổ sung thêm các thí sinh đạt giải Nhất, Nhì, Ba trong kỳ thi chọn học sinh giỏi quốc gia các môn Toán, Vật lí, Hóa học và Tin học sẽ được cấp học bổng miễn 100% học phí trong toàn bộ thời gian học tập tại trường (với điều kiện duy trì kết quả học tập loại Giỏi).</p>\n\n<p style=\"text-align: justify\">Đây là một phần trong chiến lược dài hạn của Học viện nhằm phát hiện, bồi dưỡng và trọng dụng nhân tài trong các lĩnh vực khoa học cơ bản và công nghệ mũi nhọn. Đại diện Học viện cho biết, việc đầu tư vào những sinh viên xuất sắc ngay từ đầu vào là yếu tố then chốt để xây dựng đội ngũ chuyên gia chất lượng cao cho đất nước trong tương lai.</p>\n\n<p style=\"text-align: justify\">Ngoài ra, các chính sách học bổng khác như miễn học phí năm thứ nhất cho các thí sinh đạt điểm cao trong kỳ thi tốt nghiệp THPT hoặc các kỳ thi đánh giá năng lực vẫn được duy trì theo đúng kế hoạch đã công bố.</p>\n\n<p style=\"text-align: justify\">Thông tin chi tiết về các diện xét cấp học bổng, thí sinh và phụ huynh có thể tham khảo trực tiếp trên cổng thông tin tuyển sinh của Học viện tại địa chỉ tuyensinh.ptit.edu.vn.</p>','/images/post_24/1.jpg','Học bổng','28/03/2026','ptit'),(25,'06 sinh viên PTIT xuất sắc trúng tuyển học bổng 100% chương trình thực tập tốt nghiệp tại CHLB Đức năm 2024','hoc-vien-cong-nghe-buu-chinh-vien-thong-thong-bao-danh-sach-sinh-vien-trung-tuyen-hoc-bong-100-chuong-trinh-thuc-tap-tot-nghiep-tai-chlb-duc-nam-2024','Qua 2 vòng tuyển chọn và phỏng vấn, 06 sinh viên Học viện Công nghệ Bưu chính Viễn thông đã xuất sắc trúng tuyển học bổng 100% chương trình thực tập tốt nghiệp tại CHLB Đức năm 2024.','<p style=\"text-align: justify\"><em><strong>Qua 2 vòng tuyển chọn và phỏng vấn, 06 sinh viên Học viện Công nghệ Bưu chính Viễn thông Vương Tùng Lâm; Vũ Mai Linh; Nguyễn Ngọc Minh; Nguyễn Viết Quang; Đoàn Thế Phúc; Cao Hồng Đức đã xuất sắc trúng tuyển học bổng 100% chương trình thực tập tốt nghiệp tại CHLB Đức năm 2024. Thời gian thực tập dự kiến của chương trình là 6 tháng, bắt đầu từ tháng 8/2024 đến tháng 2/2025.</strong></em></p>\n\n<div class=\"wp-caption aligncenter\">\n    <img class=\"size-full\" src=\"/images/post_25/1.png\" alt=\"Danh sách sinh viên trúng tuyển\" />\n    <p class=\"wp-caption-text\">Học viện Công nghệ Bưu chính Viễn thông công bố danh sách sinh viên trúng tuyển học bổng chương trình thực tập tại CHLB Đức năm 2024</p>\n</div>\n\n<p style=\"text-align: justify\">Chương trình học bổng toàn phần thực tập tại Đức cho sinh viên đang học tập tại Học viện Công nghệ Bưu chính Viễn thông là chương trình nằm trong khuôn khổ hợp tác giữa Học viện Công nghệ Bưu chính Viễn thông (PTIT) và Briese Schiffahrt GmbH & Co. KG (Briese Group) và sẽ được bắt đầu từ năm 2024. Mục tiêu của chương trình là trao cơ hội cho các sinh viên ngành Công nghệ thông tin, cho phép sinh viên áp dụng kiến thức trong môi trường thực tế, thúc đẩy sự phát triển kỹ năng thực tế, nâng cao khả năng làm việc. Bên cạnh đó, đây cũng là cơ hội để sinh viên được tiếp xúc với công nghệ và quy trình làm việc tiên tiến tại một công ty hàng đầu tại CHLB Đức.</p>\n\n<p style=\"text-align: justify\">Trung tâm Đào tạo Quốc tế – Học viện Công nghệ Bưu chính Viễn thông là đơn vị đầu mối, đã tiếp nhận 20 hồ sơ hợp lệ của các ứng viên tiềm năng. Qua 2 vòng tuyển chọn và phỏng vấn trực tiếp với Công ty Briese Schiffahrts, vượt qua các tiêu chí mà đơn vị đưa ra: Trình độ tiếng Anh; Kỹ năng chuyên môn trong các lĩnh vực cụ thể cần thiết cho Briese Group; Tư duy kỹ thuật; Kỹ năng mềm và Kinh nghiệm làm việc thực tế, 6 sinh viên đã xuất sắc trúng tuyển chương trình bao gồm:</p>\n\n<ol>\n<li>Vương Tùng Lâm – Lớp D20CNPM6</li>\n<li>Vũ Mai Linh – Lớp E20CQCN01-B</li>\n<li>Nguyễn Ngọc Minh – Lớp E20CQCN01-B</li>\n<li>Nguyễn Viết Quang – Lớp D20CNPM4</li>\n<li>Đoàn Thế Phúc – Lớp D20CNPM6</li>\n<li>Cao Hồng Đức – Lớp D21CNPM3</li>\n</ol>\n\n<p style=\"text-align: justify\">Các sinh viên trúng tuyển chương trình sẽ nhận được học bổng toàn phần trị giá 7000 EUR/sinh viên. Cụ thể bao gồm: Chi phí vé máy bay di chuyển 2 chiều; Chi phí/ lệ phí xin visa; Chi phí lưu trú trong thời gian thực tập tại CHLB Đức; Học bổng hàng tháng 600 EUR/ tháng.</p>\n\n<p style=\"text-align: justify\">Dự kiến, các sinh viên sẽ bắt đầu chương trình thực tập tại Đức vào cuối tháng 8/2024 và hoàn thành chương trình vào tháng 2/2025. Trong thời gian thực tập, các sinh viên sẽ làm việc tại thành phố Leer – CHLB Đức, trực tiếp tham gia vào các dự án phát triển phần mềm, tham gia các buổi thảo luận trao đổi kinh nghiệm chuyên môn, văn hóa cũng như về cuộc sống tại Đức. Bên cạnh đó sẽ tham quan các thành phố khác tại Đức, tham gian thực tế các doanh nghiệp.</p>\n\n<p style=\"text-align: justify\">Đặc biệt, Học viện Công nghệ Bưu chính Viễn thông cũng tạo điều kiện để các sinh viên được lựa chọn quy đổi/công nhận kết quả của chương trình thực tập cho điểm thực tập tốt nghiệp trong chương trình đào tạo và có thể bảo vệ đồ án tốt nghiệp theo hình thức online tại CHLB Đức (Nếu đảm bảo đủ các điều kiện để bảo vệ đồ án tốt nghiệp theo quy định).</p>','/images/post_25/1.png','Học bổng','12/07/2024','ptit'),(26,'THÔNG BÁO TUYỂN SINH ĐẠI HỌC CHÍNH QUY NĂM 2026','thong-bao-tuyen-sinh-dai-hoc-chinh-quy-nam-2026','Căn cứ Thông tư số 06/2026/TT-BGDĐT ngày 15/02/2026 của Bộ trưởng Bộ Giáo dục và Đào tạo về việc ban hành Quy chế tuyển sinh các ngành đào tạo trình độ đại học và ngành Giáo dục Mầm non trình độ cao đẳng; Căn cứ Quyết định...','<p style=\"text-align: justify\">Căn cứ <em>Thông tư số 06/2026/TT-BGDĐT ngày 15/02/2026 của Bộ trưởng Bộ Giáo dục và Đào tạo</em> về việc<em> ban hành Quy chế tuyển sinh các ngành đào tạo trình độ đại học và ngành Giáo dục Mầm non trình độ cao đẳng;</em></p>\n<p style=\"text-align: justify\">Căn cứ <em>Quyết định số 426/QĐ-HV ngày 05/03/2026 của Giám đốc Học viện Công nghệ Bưu chính Viễn thông </em>về việc<em> ban hành Quy chế tuyển sinh đại học của Học viện Công nghệ Bưu chính Viễn thông</em>;</p>\n<p style=\"text-align: justify\"><em>Căn cứ Quyết định số 1192/QĐ-HV ngày 29/04/2026 của Giám đốc Học viện Công nghệ Bưu chính Viễn thông </em>về việc phê duyệt<em> Thông tin tuyển sinh đại học năm 2026,</em></p>\n<p style=\"text-align: justify\"><em>Căn cứ Quyết định số 1256/QĐ-HV ngày 07/05/2026 của Giám đốc Học viện Công nghệ Bưu chính Viễn thông </em>về việc sửa đổi, bổ sung một số nội dung<em> Thông tin tuyển sinh đại học năm 2026,</em></p>\n<p style=\"text-align: justify\">Học viện Công nghệ Bưu chính Viễn thông thông báo tuyển sinh đại học chính quy năm 2026 như sau:</p>\n\n<p style=\"text-align: justify\"><strong>A. CHỈ TIÊU TUYỂN SINH:</strong></p>\n<p style=\"text-align: justify\"><strong>1) CƠ SỞ ĐÀO TẠO PHÍA BẮC </strong>(Mã trường: <strong>BVH</strong>)</p>\n<p style=\"text-align: justify; padding-left: 40px\"><em>Địa chỉ: Số 96A Trần Phú, Phường Hà Đông, Thành phố Hà Nội</em></p>\n\n<div style=\"overflow-x: auto;\">\n    <table border=\"1\" style=\"border-collapse: collapse; width: 100%; text-align: center; min-width: 800px;\">\n        <thead>\n            <tr style=\"background-color: #f2f2f2;\">\n                <th style=\"padding: 10px;\">TT</th>\n                <th style=\"padding: 10px;\">Mã xét tuyển</th>\n                <th style=\"padding: 10px;\">Tên ngành/chương trình xét tuyển</th>\n                <th style=\"padding: 10px;\">Mã ngành</th>\n                <th style=\"padding: 10px;\">Số lượng dự kiến</th>\n                <th style=\"padding: 10px;\">Phương thức tuyển sinh</th>\n            </tr>\n        </thead>\n        <tbody>\n            <tr style=\"background-color: #f9f9f9;\">\n                <td><strong>I</strong></td>\n                <td colspan=\"3\" style=\"text-align: left; padding-left: 15px;\"><strong>CHƯƠNG TRÌNH ĐÀO TẠO TÀI NĂNG – THẠC SĨ TÍCH HỢP CỬ NHÂN (*)</strong></td>\n                <td></td>\n                <td></td>\n            </tr>\n            <tr>\n                <td>1</td>\n                <td>8480101</td>\n                <td style=\"text-align: left; padding-left: 10px;\">Khoa học máy tính</td>\n                <td>8480101</td>\n                <td>30</td>\n                <td rowspan=\"5\" style=\"padding: 10px;\">Xét tuyển thẳng và Phương thức tuyển sinh 5</td>\n            </tr>\n            <tr>\n                <td>2</td>\n                <td>8480104</td>\n                <td style=\"text-align: left; padding-left: 10px;\">Hệ thống thông tin</td>\n                <td>8480104</td>\n                <td>30</td>\n            </tr>\n            <tr>\n                <td>3</td>\n                <td>8480202</td>\n                <td style=\"text-align: left; padding-left: 10px;\">An toàn thông tin</td>\n                <td>8480202</td>\n                <td>30</td>\n            </tr>\n            <tr>\n                <td>4</td>\n                <td>8520208</td>\n                <td style=\"text-align: left; padding-left: 10px;\">Kỹ thuật viễn thông</td>\n                <td>8520208</td>\n                <td>30</td>\n            </tr>\n            <tr>\n                <td>5</td>\n                <td>8520203</td>\n                <td style=\"text-align: left; padding-left: 10px;\">Kỹ thuật điện tử</td>\n                <td>8520203</td>\n                <td>30</td>\n            </tr>\n            \n            <tr style=\"background-color: #f9f9f9;\">\n                <td><strong>II</strong></td>\n                <td colspan=\"3\" style=\"text-align: left; padding-left: 15px;\"><strong>NGÀNH/CHƯƠNG TRÌNH ĐÀO TẠO ĐẠI TRÀ</strong></td>\n                <td></td>\n                <td></td>\n            </tr>\n            <tr>\n                <td>1</td>\n                <td>7520207</td>\n                <td style=\"text-align: left; padding-left: 10px;\">Kỹ thuật Điện tử viễn thông</td>\n                <td>7520207</td>\n                <td>410</td>\n                <td rowspan=\"10\" style=\"padding: 10px; text-align: left;\">\n                    <em>Phương thức tuyển sinh: 1, 2, 3, 4, 5</em><br><br>\n                    <em>Tổ hợp xét tuyển:</em><br>\n                    A00: Toán, Lí, Hóa;<br>\n                    A01: Toán, Lí, Anh;<br>\n                    X06: Toán, Lí, Tin;<br>\n                    X26: Toán, Tin, Anh.\n                </td>\n            </tr>\n            <tr>\n                <td>2</td>\n                <td>7520207_ AIoT</td>\n                <td style=\"text-align: left; padding-left: 10px;\">Trí tuệ nhân tạo vạn vật (AIoT)</td>\n                <td>7520207</td>\n                <td>90</td>\n            </tr>\n            <tr>\n                <td>3</td>\n                <td>7520216</td>\n                <td style=\"text-align: left; padding-left: 10px;\">Kỹ thuật Điều khiển và tự động hóa</td>\n                <td>7520216</td>\n                <td>80</td>\n            </tr>\n            <tr>\n                <td>4</td>\n                <td>7510301</td>\n                <td style=\"text-align: left; padding-left: 10px;\">Công nghệ Kỹ thuật Điện, điện tử</td>\n                <td>7510301</td>\n                <td>260</td>\n            </tr>\n            <tr>\n                <td>5</td>\n                <td>7510301_MBD</td>\n                <td style=\"text-align: left; padding-left: 10px;\">Công nghệ vi mạch bán dẫn</td>\n                <td>7510301</td>\n                <td>175</td>\n            </tr>\n            <tr>\n                <td>6</td>\n                <td>7480201</td>\n                <td style=\"text-align: left; padding-left: 10px;\">Công nghệ thông tin</td>\n                <td>7480201</td>\n                <td>600</td>\n            </tr>\n            <tr>\n                <td>7</td>\n                <td>7480107</td>\n                <td style=\"text-align: left; padding-left: 10px;\">Trí tuệ nhân tạo</td>\n                <td>7480107</td>\n                <td>160</td>\n            </tr>\n            <tr>\n                <td>8</td>\n                <td>7480202</td>\n                <td style=\"text-align: left; padding-left: 10px;\">An toàn thông tin</td>\n                <td>7480202</td>\n                <td>200</td>\n            </tr>\n            <tr>\n                <td>9</td>\n                <td>7480101</td>\n